INSERT INTO medical_exams ("id", "name", "slug", "category", "shortAnswer", "indications", "procedure", "preparation", "precautions", "durationMin", "priceMin", "priceMax", "reimbursement", "faqJson", "synonyms", "specialtyId", "relatedSlugs", "glossarySlugs", "sources", "nameAr", "shortAnswerAr", "indicationsAr", "procedureAr", "preparationAr", "precautionsAr", "reimbursementAr", "faqJsonAr", "sourcesAr", "arReviewedAt", "reviewedAt", "status", "views", "createdAt", "updatedAt")
VALUES
  ('cmrtf0z99000dy4hlboanrx90', 'Amniocentèse', 'amniocentese', 'exploration', 'L''amniocentèse prélève un peu de liquide amniotique autour du fœtus, à l''aide d''une fine aiguille guidée par échographie. Elle recherche des anomalies chromosomiques (comme la trisomie 21) ou certaines maladies. Elle est proposée dans des situations à risque, après information et consentement.', 'Risque accru d''anomalie chromosomique (âge, dépistage)
Signes échographiques particuliers
Antécédents familiaux de maladie génétique
Recherche d''une infection fœtale', 'Sous contrôle échographique, une fine aiguille traverse la paroi abdominale
Un peu de liquide amniotique est prélevé
Un repos est conseillé après le geste', 'Vessie parfois pleine selon consignes. Signaler votre groupe sanguin (Rhésus).', 'Petit risque de complication (à discuter avec le médecin)
Surveiller contractions, pertes ou fièvre après le geste', 15, 1500, 3500, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''amniocentèse est-elle douloureuse ?","a":"La piqûre est brève et généralement peu douloureuse. Un léger inconfort abdominal peut suivre le geste."},{"q":"Est-elle obligatoire ?","a":"Non. Elle est proposée dans certaines situations à risque et réalisée uniquement après information et votre consentement."}]', ARRAY['Prélèvement de liquide amniotique']::text[], (SELECT id FROM specialties WHERE slug='gyneco-obstetrique'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'بزل السائل الأمنيوسي', 'يأخذ بزل السائل الأمنيوسي قليلاً من السائل المحيط بالجنين بواسطة إبرة دقيقة موجَّهة بالصدى. يبحث عن شذوذات صبغية (مثل متلازمة داون) أو بعض الأمراض. يُقترح في الحالات المعرّضة للخطر بعد إعلام وموافقة.', 'خطر متزايد لشذوذ صبغي (السن، الفحص)
علامات خاصة في التصوير بالصدى
سوابق عائلية لمرض وراثي
البحث عن عدوى جنينية', 'تحت مراقبة الصدى تعبر إبرة دقيقة جدار البطن
يُؤخذ قليل من السائل الأمنيوسي
يُنصح بالراحة بعد الإجراء', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z9m000fy4hl4uc0sa9l', 'Analyse d''urine (ECBU)', 'analyse-urine', 'biologie', 'L''analyse d''urine (bandelette et ECBU) recherche une infection urinaire, du sucre, des protéines ou du sang dans les urines. Simple et indolore, elle aide à diagnostiquer une infection, à surveiller le diabète ou les reins. Le recueil doit être réalisé proprement.', 'Suspicion d''infection urinaire (brûlures, envies fréquentes)
Surveillance du diabète et des reins
Recherche de sang ou de protéines dans les urines
Bilan de santé', 'Vous recueillez les urines dans un flacon stérile après une toilette préalable
Une bandelette et/ou une analyse en laboratoire sont réalisées
L''ECBU recherche et identifie une éventuelle infection', 'Toilette intime avant le recueil ; privilégier les premières urines du matin, jet du milieu.', 'Un recueil non stérile peut fausser le résultat.', 5, 80, 250, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Comment bien recueillir les urines ?","a":"Après une toilette intime, éliminez le premier jet puis recueillez le jet du milieu dans un flacon stérile, idéalement le matin."},{"q":"L''analyse détecte-t-elle le diabète ?","a":"La présence de sucre dans les urines peut orienter vers un diabète, mais le diagnostic repose surtout sur la glycémie sanguine."}]', ARRAY['ECBU','Examen des urines','Analyse urinaire']::text[], (SELECT id FROM specialties WHERE slug='biologie-medicale'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تحليل البول', 'يبحث تحليل البول عن التهاب بولي أو سكر أو بروتينات أو دم في البول. بسيط وغير مؤلم، ويساعد على تشخيص العدوى ومراقبة السكري أو الكلى. يجب جمع العينة بطريقة نظيفة.', 'اشتباه بالتهاب بولي (حرقة، تبوّل متكرر)
مراقبة السكري والكلى
البحث عن دم أو بروتينات في البول
تقييم صحي', 'تجمع البول في وعاء معقّم بعد تنظيف مسبق
يُجرى تحليل بشريط و/أو في المختبر
يبحث الفحص عن عدوى ويحدّدها', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z8c0008y4hlw4kgrqn2', 'Audiogramme (test auditif)', 'audiogramme', 'exploration', 'L''audiogramme mesure l''audition en présentant, dans un casque, des sons de différentes fréquences et intensités. Indolore, il évalue une baisse d''audition, des acouphènes ou des vertiges et aide à choisir une éventuelle correction auditive.', 'Baisse de l''audition
Acouphènes (bourdonnements)
Bilan de vertiges
Dépistage auditif (enfant, exposition au bruit)', 'Dans une cabine insonorisée, vous portez un casque
Vous signalez chaque son entendu (bouton ou geste)
L''audition de chaque oreille est mesurée séparément', 'Aucune préparation particulière.', 'Examen sans danger.', 20, 150, 400, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''audiogramme est-il fiable chez l''enfant ?","a":"Oui, des tests adaptés à l''âge existent, y compris chez le jeune enfant, pour dépister une baisse d''audition."},{"q":"Combien de temps dure le test ?","a":"En général une vingtaine de minutes, sans aucune douleur."}]', ARRAY['Audiométrie','Test auditif']::text[], (SELECT id FROM specialties WHERE slug='oto-rhino-laryngologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'مخطط السمع (اختبار السمع)', 'يقيس مخطط السمع القدرة السمعية بعرض أصوات بترددات وشدّات مختلفة عبر سماعة. غير مؤلم، ويقيّم ضعف السمع أو الطنين أو الدوار، ويساعد على اختيار تصحيح سمعي محتمل.', 'ضعف السمع
طنين الأذن
تقييم الدوار
كشف سمعي (طفل، تعرّض للضجيج)', 'في مقصورة عازلة للصوت ترتدي سماعة
تشير إلى كل صوت تسمعه (زر أو إشارة)
يُقاس سمع كل أذن على حدة', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0za6000jy4hl5hkyuiwe', 'Biopsie', 'biopsie', 'anatomopathologie', 'Une biopsie prélève un petit fragment de tissu (peau, sein, foie, prostate…) pour l''analyser au microscope. C''est souvent l''examen qui confirme ou écarte un diagnostic, notamment un cancer. Elle est réalisée sous anesthésie locale, avec ou sans guidage par imagerie.', 'Confirmation d''un diagnostic (dont cancer)
Analyse d''une lésion, d''une masse ou d''un ganglion
Bilan d''une maladie de la peau, du foie ou du rein
Caractérisation d''une anomalie détectée en imagerie', 'La zone est anesthésiée localement
Un fragment de tissu est prélevé (aiguille, pince ou petite incision)
L''échantillon est analysé par un médecin anatomopathologiste', 'Signaler les traitements anticoagulants. Consignes spécifiques selon l''organe concerné.', 'Troubles de la coagulation
Petit risque de saignement ou d''infection au point de prélèvement', 20, 500, 2000, 'Prise en charge partielle par l''AMO/CNSS ; l''analyse anatomopathologique peut s''ajouter.', '[{"q":"La biopsie fait-elle mal ?","a":"Elle est réalisée sous anesthésie locale, elle est donc peu douloureuse. Une gêne au point de prélèvement peut persister brièvement."},{"q":"Quand a-t-on les résultats ?","a":"L''analyse au microscope demande généralement quelques jours à deux semaines selon le type de prélèvement."}]', ARRAY['Prélèvement biopsique','Ponction-biopsie']::text[], (SELECT id FROM specialties WHERE slug='anatomo-pathologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الخزعة', 'تأخذ الخزعة جزءاً صغيراً من نسيج (جلد، ثدي، كبد، بروستات…) لتحليله بالمجهر. غالباً هي الفحص الذي يؤكّد أو ينفي تشخيصاً، لا سيما السرطان. تُجرى تحت تخدير موضعي، مع أو دون توجيه بالتصوير.', 'تأكيد تشخيص (منها السرطان)
تحليل آفة أو كتلة أو عقدة لمفية
تقييم مرض في الجلد أو الكبد أو الكلى
توصيف شذوذ كُشف بالتصوير', 'تُخدَّر المنطقة موضعياً
يُؤخذ جزء من النسيج (إبرة أو ملقط أو شق صغير)
يحلّل العينة طبيب علم الأمراض النسيجي', NULL, NULL, 'تعويض جزئي من AMO/CNSS؛ قد يُضاف التحليل النسيجي.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7a60008eghl9w8mfosq', 'Coloscopie', 'coloscopie', 'exploration', 'La coloscopie explore l''intérieur du gros intestin (côlon) à l''aide d''une caméra souple introduite par l''anus. Réalisée sous anesthésie, elle dépiste et traite les polypes, recherche un cancer colorectal et explore des saignements ou des troubles digestifs. Elle dure environ 30 minutes.', 'Dépistage du cancer colorectal
Détection et ablation de polypes
Exploration de saignements digestifs ou d''anémie inexpliquée
Bilan de douleurs abdominales ou de troubles du transit persistants', 'L''examen est réalisé sous anesthésie (générale légère ou sédation)
Le médecin introduit un endoscope souple par l''anus pour explorer tout le côlon
Des polypes peuvent être retirés et des biopsies réalisées pendant l''examen', 'Régime sans résidu quelques jours avant, puis prise d''une solution de purge pour vider complètement le côlon.
Jeûne avant l''examen. Organiser un accompagnant en raison de l''anesthésie.', 'Bilan pré-anesthésique nécessaire
Signaler un traitement anticoagulant ou antiagrégant (adaptation avant l''examen)
Rares complications (saignement, perforation) à discuter avec le médecin', 30, 1500, 4000, 'Prise en charge partielle par l''AMO/CNSS ; l''anesthésie et l''hospitalisation de jour peuvent s''ajouter.', '[{"q":"La coloscopie est-elle douloureuse ?","a":"Elle est réalisée sous anesthésie ou sédation, vous ne ressentez donc pas de douleur pendant l''examen. La préparation (purge) est la partie la plus contraignante."},{"q":"Pourquoi la préparation est-elle importante ?","a":"Un côlon parfaitement propre est indispensable pour bien visualiser la paroi et ne manquer aucun polype ou lésion."}]', ARRAY['Colonoscopie','Endoscopie colique']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تنظير القولون', 'يستكشف تنظير القولون داخل الأمعاء الغليظة بواسطة كاميرا مرنة تُدخل عبر الشرج. يُجرى تحت التخدير، ويكشف ويعالج السلائل، ويبحث عن سرطان القولون والمستقيم، ويستكشف النزيف أو الاضطرابات الهضمية. يستغرق نحو 30 دقيقة.', 'الكشف عن سرطان القولون والمستقيم
كشف واستئصال السلائل
استكشاف نزيف هضمي أو فقر دم غير مفسّر
تقييم آلام بطنية أو اضطرابات هضمية مستمرة', 'يُجرى الفحص تحت التخدير (عام خفيف أو تهدئة)
يُدخل الطبيب منظاراً مرناً عبر الشرج لاستكشاف كامل القولون
يمكن استئصال السلائل وأخذ خزعات أثناء الفحص', NULL, NULL, 'تعويض جزئي من AMO/CNSS؛ قد يُضاف التخدير والاستشفاء اليومي.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z7c0003y4hl5cnthzo1', 'Coronarographie', 'coronarographie', 'imagerie', 'La coronarographie visualise les artères du cœur (coronaires) grâce à un produit de contraste et des rayons X, via un cathéter introduit au poignet ou à l''aine. Elle recherche un rétrécissement des coronaires et permet souvent de le traiter dans le même temps (angioplastie).', 'Suspicion ou bilan de maladie coronarienne
Après un infarctus ou un angor instable
Bilan avant chirurgie cardiaque
Douleurs thoraciques avec tests non concluants', 'Réalisée à l''hôpital sous anesthésie locale
Un cathéter est introduit par le poignet ou l''aine jusqu''au cœur
Un produit de contraste est injecté et des images sont prises ; une angioplastie peut suivre', 'Bilan sanguin préalable et jeûne avant l''examen. Signaler allergies et traitements anticoagulants.', 'Allergie à l''iode
Insuffisance rénale
Troubles de la coagulation', 45, 4000, 10000, 'Acte hospitalier : prise en charge partielle par l''AMO/CNSS ; hospitalisation et éventuelle angioplastie en supplément.', '[{"q":"La coronarographie est-elle douloureuse ?","a":"Réalisée sous anesthésie locale, elle est peu douloureuse ; vous pouvez ressentir une chaleur brève lors de l''injection du produit."},{"q":"Peut-on traiter pendant l''examen ?","a":"Oui, si un rétrécissement significatif est trouvé, une angioplastie (pose de stent) peut souvent être réalisée dans le même temps."}]', ARRAY['Angiographie coronaire']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تصوير الشرايين التاجية', 'يُظهر تصوير الشرايين التاجية شرايين القلب بواسطة مادة تباين وأشعة سينية عبر قسطرة تُدخل من المعصم أو الأربية. يبحث عن تضيّق الشرايين التاجية وغالباً يعالجه في الوقت نفسه (رأب الأوعية).', 'اشتباه أو تقييم مرض الشرايين التاجية
بعد احتشاء أو ذبحة غير مستقرة
تقييم قبل جراحة القلب
ألم صدري مع فحوصات غير حاسمة', 'تُجرى في المستشفى تحت تخدير موضعي
تُدخل قسطرة من المعصم أو الأربية حتى القلب
تُحقن مادة تباين وتُلتقط الصور؛ وقد يليها رأب للأوعية', NULL, NULL, 'إجراء استشفائي: تعويض جزئي من AMO/CNSS؛ يُضاف الاستشفاء ورأب الأوعية عند اللزوم.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei79f0005eghlk817v18j', 'Écho-Doppler vasculaire', 'echo-doppler', 'imagerie', 'L''écho-Doppler associe l''échographie à l''étude du flux sanguin pour évaluer les artères et les veines. Indolore et sans rayons X, il recherche notamment une phlébite, des varices, un rétrécissement artériel ou surveille la circulation, en général en 20 à 40 minutes.', 'Recherche de phlébite (thrombose veineuse)
Bilan de varices ou d''insuffisance veineuse
Évaluation des artères (carotides, membres inférieurs)
Surveillance après chirurgie vasculaire', 'Un gel est appliqué et le médecin déplace une sonde sur le trajet des vaisseaux
L''appareil restitue un signal sonore du flux sanguin
Des mesures de vitesse et de calibre sont réalisées', 'Aucune préparation particulière dans la plupart des cas.', 'Aucune contre-indication : examen non irradiant et non invasif.', 30, 400, 900, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''écho-Doppler est-il douloureux ?","a":"Non, l''examen est indolore. La sonde glisse simplement sur la peau enduite de gel."},{"q":"Quand prescrit-on un écho-Doppler des jambes ?","a":"Souvent devant une jambe gonflée et douloureuse (suspicion de phlébite), des varices, ou pour évaluer la circulation artérielle."}]', ARRAY['Doppler','Échographie Doppler']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Société française de radiologie","url":"https://www.sfrnet.org","publisher":"SFR"}]', 'تصوير دوبلر الوعائي', 'يجمع تصوير دوبلر بين التصوير بالصدى ودراسة تدفق الدم لتقييم الشرايين والأوردة. غير مؤلم وبدون أشعة، يبحث عن التهاب وريدي أو دوالي أو تضيق شرياني، عادة في 20 إلى 40 دقيقة.', 'البحث عن التهاب وريدي (خثار وريدي)
تقييم الدوالي أو القصور الوريدي
تقييم الشرايين (السباتية، الأطراف السفلية)', 'يُوضع هلام ويحرّك الطبيب المجس على مسار الأوعية
يصدر الجهاز إشارة صوتية لتدفق الدم
تُجرى قياسات للسرعة والقُطر', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z6a0000y4hlfemlhc2d', 'Échocardiographie (échographie du cœur)', 'echocardiographie', 'imagerie', 'L''échocardiographie est une échographie du cœur : grâce aux ultrasons, elle visualise en temps réel les cavités, les valves et le fonctionnement du muscle cardiaque. Indolore et sans rayons X, elle évalue un souffle, une insuffisance cardiaque ou une maladie des valves. Elle dure environ 20 minutes.', 'Bilan d''un souffle au cœur
Évaluation d''une insuffisance cardiaque
Suivi d''une maladie des valves
Bilan d''essoufflement ou de palpitations', 'Un gel est appliqué sur le thorax et le médecin déplace une sonde
Les images du cœur s''affichent en temps réel
Le flux sanguin est analysé (Doppler cardiaque)', 'Aucune préparation particulière.', 'Examen sans danger, non irradiant et non invasif.', 20, 300, 800, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''échocardiographie est-elle douloureuse ?","a":"Non, elle est indolore. La sonde glisse simplement sur la peau enduite de gel."},{"q":"Quelle différence avec l''ECG ?","a":"L''ECG enregistre l''activité électrique du cœur ; l''échocardiographie montre sa structure et son mouvement en images."}]', ARRAY['Écho du cœur','Échocardiogramme']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تخطيط صدى القلب', 'تخطيط صدى القلب هو تصوير بالصدى للقلب: بفضل الموجات فوق الصوتية يُظهر مباشرةً التجاويف والصمامات وعمل عضلة القلب. غير مؤلم وبدون أشعة، ويقيّم النفخة أو قصور القلب أو مرض الصمامات. يستغرق نحو 20 دقيقة.', 'تقييم نفخة قلبية
تقييم قصور القلب
متابعة مرض الصمامات
تقييم ضيق التنفس أو الخفقان', 'يُوضع هلام على الصدر ويحرّك الطبيب المجس
تظهر صور القلب مباشرة على الشاشة
يُحلَّل تدفق الدم (دوبلر قلبي)', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei78w0003eghl42pc8kur', 'Échographie', 'echographie', 'imagerie', 'L''échographie utilise des ultrasons (et non des rayons X) pour visualiser en temps réel les organes, les vaisseaux ou le fœtus. Indolore et sans danger, elle explore l''abdomen, le pelvis, la thyroïde, les seins ou le suivi de grossesse, en général en 15 à 30 minutes.', 'Suivi de grossesse
Exploration de l''abdomen (foie, vésicule, reins)
Bilan de la thyroïde ou des seins
Étude des vaisseaux et du cœur (échocardiographie)', 'Un gel est appliqué sur la peau pour la transmission des ultrasons
Le médecin déplace une sonde sur la zone à explorer
Les images s''affichent en temps réel sur un écran', 'Vessie pleine pour une échographie pelvienne.
Jeûne de quelques heures pour une échographie abdominale.
Aucune préparation pour la plupart des autres échographies.', 'Aucune contre-indication : l''échographie n''utilise pas de rayonnement ionisant.', 20, 250, 700, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''échographie est-elle sans danger pendant la grossesse ?","a":"Oui. L''échographie n''utilise pas de rayons X et est l''examen de référence pour le suivi de grossesse."},{"q":"Pourquoi faut-il parfois avoir la vessie pleine ?","a":"Pour l''échographie pelvienne, une vessie pleine repousse les intestins et offre une meilleure visualisation des organes du bas-ventre."}]', ARRAY['Écho','Ultrasons','Échographie médicale']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Société française de radiologie","url":"https://www.sfrnet.org","publisher":"SFR"}]', 'التصوير بالصدى (الإيكوغرافيا)', 'يستخدم التصوير بالصدى الموجات فوق الصوتية (وليس الأشعة السينية) لرؤية الأعضاء والأوعية أو الجنين مباشرة. فحص غير مؤلم وآمن يستكشف البطن والحوض والغدة الدرقية والثديين ومتابعة الحمل، عادة في 15 إلى 30 دقيقة.', 'متابعة الحمل
استكشاف البطن (الكبد، المرارة، الكلى)
تقييم الغدة الدرقية أو الثديين
دراسة الأوعية والقلب', 'يُوضع هلام على الجلد لنقل الموجات
يحرّك الطبيب المجس على المنطقة
تظهر الصور مباشرة على الشاشة', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei79o0006eghl67mabcpo', 'Électrocardiogramme (ECG)', 'electrocardiogramme', 'exploration', 'L''électrocardiogramme (ECG) enregistre l''activité électrique du cœur à l''aide d''électrodes posées sur la peau. Rapide (quelques minutes) et indolore, il détecte les troubles du rythme, un infarctus ou d''autres anomalies cardiaques.', 'Douleur thoracique ou palpitations
Bilan d''essoufflement ou de malaise
Surveillance d''une maladie cardiaque connue
Bilan avant une intervention chirurgicale', 'Des électrodes autocollantes sont placées sur la poitrine, les poignets et les chevilles
Vous restez allongé et immobile quelques minutes
L''appareil enregistre le tracé du cœur', 'Aucune préparation nécessaire. Évitez les crèmes sur la poitrine le jour de l''examen.', 'Examen sans danger, non invasif et non irradiant.', 10, 100, 250, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''ECG envoie-t-il de l''électricité dans le corps ?","a":"Non. L''ECG ne fait qu''enregistrer l''activité électrique naturelle du cœur ; il n''émet aucun courant."},{"q":"Combien de temps dure un ECG ?","a":"L''enregistrement lui-même ne dure que quelques minutes."}]', ARRAY['ECG','Électrocardiogramme']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تخطيط القلب الكهربائي (ECG)', 'يسجّل تخطيط القلب الكهربائي النشاط الكهربائي للقلب عبر أقطاب توضع على الجلد. سريع (بضع دقائق) وغير مؤلم، يكشف اضطرابات النظم أو احتشاء القلب أو تشوهات قلبية أخرى.', 'ألم في الصدر أو خفقان
تقييم ضيق التنفس أو الإغماء
مراقبة مرض قلبي معروف
تقييم قبل عملية جراحية', 'تُوضع أقطاب لاصقة على الصدر والمعصمين والكاحلين
تبقى مستلقياً دون حركة بضع دقائق
يسجّل الجهاز مخطط القلب', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z7r0005y4hlv18pp73n', 'Électroencéphalogramme (EEG)', 'electroencephalogramme', 'exploration', 'L''électroencéphalogramme (EEG) enregistre l''activité électrique du cerveau grâce à des électrodes posées sur le cuir chevelu. Indolore et sans danger, il aide à explorer l''épilepsie, les malaises, certains troubles du sommeil ou des céphalées. L''examen dure environ 30 minutes.', 'Bilan d''épilepsie ou de convulsions
Exploration de malaises ou de pertes de connaissance
Certains troubles du sommeil
Bilan de céphalées ou de troubles neurologiques', 'Des électrodes sont posées sur le cuir chevelu avec un gel
Vous restez calme, parfois yeux ouverts puis fermés, avec une respiration rapide
Une stimulation lumineuse peut être utilisée', 'Cheveux propres et secs, sans gel coiffant. Suivre les consignes de sommeil pour un EEG de sieste.', 'Examen sans danger, non invasif.', 30, 300, 700, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''EEG envoie-t-il de l''électricité dans le cerveau ?","a":"Non. Il ne fait qu''enregistrer l''activité électrique naturelle du cerveau ; il n''émet aucun courant."},{"q":"Faut-il arrêter mes médicaments ?","a":"Ne modifiez rien sans avis médical. Certaines consignes (sommeil, traitements) vous seront précisées avant l''examen."}]', ARRAY['EEG']::text[], (SELECT id FROM specialties WHERE slug='neurologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تخطيط كهربية الدماغ (EEG)', 'يسجّل تخطيط كهربية الدماغ النشاط الكهربائي للدماغ عبر أقطاب توضع على فروة الرأس. غير مؤلم وآمن، ويساعد على استكشاف الصرع والإغماءات وبعض اضطرابات النوم أو الصداع. يستغرق نحو 30 دقيقة.', 'تقييم الصرع أو التشنجات
استكشاف الإغماءات أو فقدان الوعي
بعض اضطرابات النوم
تقييم الصداع أو اضطرابات عصبية', 'تُوضع أقطاب على فروة الرأس بهلام
تبقى هادئاً، أحياناً بعينين مفتوحتين ثم مغلقتين، مع تنفّس سريع
قد يُستعمل تنبيه ضوئي', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z7j0004y4hle1tgz56z', 'Électromyogramme (EMG)', 'electromyogramme', 'exploration', 'L''électromyogramme (EMG) étudie le fonctionnement des nerfs et des muscles à l''aide de petites stimulations électriques et d''une fine aiguille. Il explore les fourmillements, les faiblesses musculaires ou les douleurs, et aide à diagnostiquer un syndrome du canal carpien ou une atteinte nerveuse.', 'Fourmillements ou engourdissements persistants
Faiblesse ou fonte musculaire
Suspicion de syndrome du canal carpien
Douleurs sur le trajet d''un nerf (sciatique)', 'Des stimulations électriques légères mesurent la conduction nerveuse
Une fine aiguille explore parfois l''activité des muscles
L''examen peut être un peu désagréable mais reste bref', 'Peau propre, sans crème. Signaler un traitement anticoagulant ou un pacemaker.', 'Prudence en cas de traitement anticoagulant (partie avec aiguille).', 30, 400, 1000, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''EMG est-il douloureux ?","a":"Les stimulations donnent de petites secousses et l''aiguille une gêne brève. C''est supportable et l''examen reste court."},{"q":"À quoi sert l''EMG ?","a":"Il précise si des fourmillements ou une faiblesse viennent d''un nerf ou d''un muscle, par exemple dans le canal carpien ou une sciatique."}]', ARRAY['EMG','Électroneuromyogramme','ENMG']::text[], (SELECT id FROM specialties WHERE slug='neurologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تخطيط كهربية العضل (EMG)', 'يدرس تخطيط كهربية العضل عمل الأعصاب والعضلات عبر تنبيهات كهربائية خفيفة وإبرة دقيقة. يستكشف التنميل والضعف العضلي أو الألم، ويساعد على تشخيص متلازمة النفق الرسغي أو إصابة عصبية.', 'تنميل أو خدر مستمر
ضعف أو ضمور عضلي
اشتباه بمتلازمة النفق الرسغي
ألم على مسار عصب (عرق النسا)', 'تنبيهات كهربائية خفيفة تقيس التوصيل العصبي
قد تستكشف إبرة دقيقة نشاط العضلات
قد يكون الفحص مزعجاً قليلاً لكنه قصير', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z6x0001y4hlcb3j5fz2', 'Épreuve d''effort (ECG d''effort)', 'test-effort', 'exploration', 'L''épreuve d''effort enregistre l''activité du cœur pendant un exercice progressif sur tapis roulant ou vélo. Elle recherche une maladie des artères du cœur, évalue les douleurs thoraciques à l''effort et la tolérance cardiaque. Encadré par un médecin, l''examen dure environ 30 minutes.', 'Recherche d''une maladie des artères du cœur (coronaropathie)
Bilan de douleurs thoraciques à l''effort
Évaluation de la tolérance à l''effort
Suivi après un événement cardiaque', 'Des électrodes sont posées et vous marchez ou pédalez à intensité croissante
La tension et l''ECG sont surveillés en continu
L''examen s''arrête en cas de fatigue, de symptôme ou d''objectif atteint', 'Venir en tenue de sport, avoir mangé légèrement. Signaler vos traitements (certains sont à adapter).', 'Contre-indiqué en cas de problème cardiaque instable (à évaluer par le médecin).', 30, 400, 1000, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''épreuve d''effort est-elle dangereuse ?","a":"Elle est réalisée sous surveillance médicale continue, ce qui la rend sûre. Elle est interrompue au moindre signe anormal."},{"q":"Comment m''y préparer ?","a":"Venez en tenue de sport, avec un repas léger, et signalez vos traitements car certains doivent être adaptés."}]', ARRAY['ECG d''effort','Test d''effort']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'اختبار الجهد (تخطيط القلب بالجهد)', 'يسجّل اختبار الجهد نشاط القلب أثناء تمرين تصاعدي على جهاز المشي أو الدراجة. يبحث عن مرض شرايين القلب ويقيّم ألم الصدر عند الجهد وتحمّل القلب. تحت إشراف طبيب، يستغرق نحو 30 دقيقة.', 'البحث عن مرض شرايين القلب
تقييم ألم الصدر عند الجهد
تقييم تحمّل الجهد
متابعة بعد حدث قلبي', 'تُوضع أقطاب وتمشي أو تركب الدراجة بشدة متزايدة
يُراقَب الضغط وتخطيط القلب باستمرار
يتوقف الفحص عند التعب أو ظهور عرَض أو بلوغ الهدف', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z840007y4hl30k58ah0', 'Fond d''œil', 'fond-d-oeil', 'exploration', 'Le fond d''œil examine la rétine, le nerf optique et les vaisseaux à l''arrière de l''œil, souvent après dilatation de la pupille par un collyre. Indolore, il dépiste et surveille le diabète, l''hypertension, le glaucome ou les maladies de la rétine.', 'Surveillance du diabète et de l''hypertension
Dépistage du glaucome et de la DMLA
Bilan de baisse de vision
Maux de tête ou bilan neurologique', 'Un collyre dilate la pupille (vision floue transitoire)
Le médecin examine le fond de l''œil avec une lumière et une lentille
L''examen ne dure que quelques minutes', 'Prévoir de ne pas conduire juste après (éblouissement lié à la dilatation). Venir accompagné si possible.', 'Éblouissement et vision floue quelques heures après la dilatation.', 15, 150, 400, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Pourquoi dilate-t-on la pupille ?","a":"La dilatation permet de bien voir toute la rétine. Elle rend la vision floue et éblouie pendant quelques heures."},{"q":"Le fond d''œil fait-il mal ?","a":"Non, l''examen est indolore ; seule la lumière peut être éblouissante."}]', ARRAY['Examen de la rétine','Rétinographie']::text[], (SELECT id FROM specialties WHERE slug='ophtalmologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'فحص قاع العين', 'يفحص قاع العين الشبكية والعصب البصري والأوعية في مؤخرة العين، غالباً بعد توسيع الحدقة بقطرة. غير مؤلم، ويكشف ويراقب السكري وارتفاع الضغط والزرق أو أمراض الشبكية.', 'مراقبة السكري وارتفاع الضغط
كشف الزرق والتنكس البقعي
تقييم تراجع الرؤية
صداع أو تقييم عصبي', 'قطرة توسّع الحدقة (تشوّش مؤقت في الرؤية)
يفحص الطبيب قاع العين بضوء وعدسة
لا يستغرق الفحص سوى دقائق قليلة', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z8z000cy4hlgg2kbwnq', 'Frottis cervico-utérin', 'frottis-cervico-vaginal', 'anatomopathologie', 'Le frottis cervico-utérin prélève des cellules du col de l''utérus pour les analyser au microscope. Peu gênant, il dépiste les lésions précancéreuses et le cancer du col de l''utérus. Il est recommandé régulièrement chez la femme à partir de 25 ans.', 'Dépistage du cancer du col de l''utérus
Surveillance après un frottis anormal
Bilan gynécologique de routine
Recherche du papillomavirus (HPV) associée', 'Réalisé lors d''un examen gynécologique, avec un spéculum
Une petite brosse prélève des cellules du col
Le prélèvement est envoyé au laboratoire', 'Éviter rapports, ovules et toilette interne 48 h avant. Hors période de règles.', 'Léger inconfort ou saignement minime possible après le prélèvement.', 10, 150, 400, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Le frottis est-il douloureux ?","a":"Il est généralement peu gênant et rapide ; un léger inconfort ou un petit saignement peut survenir après."},{"q":"À quelle fréquence le faire ?","a":"En général à partir de 25 ans, puis à intervalles réguliers selon les recommandations et le type de test (cytologie ou HPV)."}]', ARRAY['Frottis','Test de dépistage du col','Pap test']::text[], (SELECT id FROM specialties WHERE slug='gyneco-obstetrique'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'مسحة عنق الرحم', 'تأخذ مسحة عنق الرحم خلايا من عنق الرحم لتحليلها بالمجهر. قليلة الإزعاج، وتكشف الآفات ما قبل السرطانية وسرطان عنق الرحم. يُنصح بها دورياً للمرأة ابتداءً من 25 سنة.', 'كشف سرطان عنق الرحم
متابعة بعد مسحة غير طبيعية
فحص نسائي روتيني
البحث عن فيروس الورم الحليمي (HPV)', 'يُجرى أثناء فحص نسائي باستخدام منظار مهبلي
تأخذ فرشاة صغيرة خلايا من العنق
تُرسل العينة إلى المختبر', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7ai0009eghlbo789u0f', 'Gastroscopie (endoscopie digestive haute)', 'gastroscopie', 'exploration', 'La gastroscopie explore l''œsophage, l''estomac et le début de l''intestin grêle à l''aide d''une caméra souple introduite par la bouche. Souvent réalisée sous sédation, elle recherche un ulcère, une inflammation, une infection à Helicobacter pylori ou une lésion, et permet des biopsies. Elle dure environ 15 minutes.', 'Douleurs de l''estomac ou brûlures persistantes
Recherche d''un ulcère ou d''Helicobacter pylori
Bilan de difficultés à avaler ou de saignements digestifs
Surveillance de lésions connues', 'Une anesthésie locale de la gorge ou une sédation légère est administrée
Le médecin introduit un endoscope souple par la bouche
Des biopsies peuvent être prélevées pendant l''examen', 'Jeûne strict de 6 heures minimum (aliments et boissons).
Signaler vos traitements ; organiser un accompagnant en cas de sédation.', 'Signaler un traitement anticoagulant
Rares complications à discuter avec le médecin
Bilan pré-anesthésique si sédation profonde', 15, 1000, 2500, 'Prise en charge partielle par l''AMO/CNSS ; sédation éventuelle en supplément.', '[{"q":"La gastroscopie fait-elle mal ?","a":"Elle est inconfortable mais généralement indolore, surtout sous sédation. L''anesthésie de la gorge limite le réflexe nauséeux."},{"q":"Combien de temps rester à jeun ?","a":"Au moins 6 heures avant l''examen, sans aliment ni boisson, pour un estomac vide et un examen sûr."}]', ARRAY['Endoscopie digestive haute','Fibroscopie gastrique','EOGD']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تنظير المعدة', 'يستكشف تنظير المعدة المريء والمعدة وبداية الأمعاء الدقيقة بواسطة كاميرا مرنة تُدخل عبر الفم. غالباً تحت تهدئة، يبحث عن قرحة أو التهاب أو جرثومة المعدة أو آفة، ويتيح أخذ خزعات. يستغرق نحو 15 دقيقة.', 'آلام أو حرقة معدية مستمرة
البحث عن قرحة أو جرثومة المعدة
تقييم صعوبة البلع أو نزيف هضمي
مراقبة آفات معروفة', 'يُعطى تخدير موضعي للحلق أو تهدئة خفيفة
يُدخل الطبيب منظاراً مرناً عبر الفم
يمكن أخذ خزعات أثناء الفحص', NULL, NULL, 'تعويض جزئي من AMO/CNSS؛ قد تُضاف التهدئة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z730002y4hl2ww7w30r', 'Holter ECG (enregistrement 24 h)', 'holter-ecg', 'exploration', 'Le Holter ECG enregistre l''activité électrique du cœur en continu pendant 24 à 48 heures, grâce à un petit boîtier porté à domicile. Il détecte les troubles du rythme intermittents, les palpitations ou les malaises qui n''apparaissent pas lors d''un ECG classique.', 'Palpitations ou malaises intermittents
Recherche de troubles du rythme cardiaque
Bilan de pertes de connaissance
Suivi d''un traitement du rythme', 'Des électrodes et un petit boîtier enregistreur sont posés
Vous rentrez chez vous et vivez normalement pendant 24 à 48 heures
Un journal des symptômes est tenu, puis le tracé est analysé', 'Aucune. Éviter de mouiller le boîtier (pas de douche pendant l''enregistrement).', 'Examen sans danger, non invasif.', NULL, 400, 900, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Puis-je vivre normalement avec le Holter ?","a":"Oui, il faut même mener une vie habituelle pour capter d''éventuelles anomalies. Évitez seulement de mouiller le boîtier."},{"q":"Pourquoi pas un simple ECG ?","a":"L''ECG classique ne dure que quelques secondes ; le Holter surveille sur 24-48 h et capte les troubles qui vont et viennent."}]', ARRAY['Holter rythmique','Holter cardiaque']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'هولتر القلب (تسجيل 24 ساعة)', 'يسجّل هولتر القلب النشاط الكهربائي للقلب باستمرار لمدة 24 إلى 48 ساعة عبر جهاز صغير يُحمل في المنزل. يكشف اضطرابات النظم المتقطعة والخفقان أو الإغماءات التي لا تظهر في تخطيط القلب العادي.', 'خفقان أو إغماءات متقطعة
البحث عن اضطرابات نظم القلب
تقييم فقدان الوعي
متابعة علاج اضطراب النظم', 'تُوضع أقطاب وجهاز تسجيل صغير
تعود إلى المنزل وتعيش بشكل طبيعي لمدة 24 إلى 48 ساعة
تدوّن مذكرة للأعراض ثم يُحلَّل التسجيل', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei77r0000eghle2yvofqc', 'IRM (imagerie par résonance magnétique)', 'irm', 'imagerie', 'L''IRM produit des images très détaillées des organes et des tissus mous grâce à un champ magnétique, sans rayons X. Indolore, elle explore notamment le cerveau, la moelle, les articulations et l''abdomen. L''examen dure en général de 15 à 45 minutes.', 'Exploration du cerveau et de la moelle épinière
Bilan des articulations (genou, épaule, rachis)
Recherche de tumeur, d''inflammation ou de lésion des tissus mous
Bilan abdominal et pelvien approfondi', 'Vous êtes allongé sur une table qui glisse dans un tunnel ouvert aux deux extrémités
Il faut rester parfaitement immobile pendant l''acquisition
L''appareil émet des bruits sourds et répétés (un casque anti-bruit est fourni)
Un produit de contraste (gadolinium) est parfois injecté', 'Aucun jeûne sauf en cas d''injection de produit de contraste (à confirmer avec le centre).
Retirer tout objet métallique (bijoux, montre, ceinture).
Signaler une éventuelle grossesse.', 'Pacemaker, défibrillateur ou implant métallique/électronique (à signaler impérativement)
Claustrophobie sévère (une sédation légère peut être proposée)
Insuffisance rénale sévère si injection de gadolinium', 30, 1500, 4000, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale et selon la tarification nationale de référence.', '[{"q":"L''IRM est-elle douloureuse ?","a":"Non, l''IRM est totalement indolore. Le principal inconfort vient du bruit de l''appareil et de la nécessité de rester immobile."},{"q":"Combien de temps dure une IRM ?","a":"Le plus souvent entre 15 et 45 minutes, selon la région du corps explorée et le nombre de séquences."},{"q":"L''IRM utilise-t-elle des rayons X ?","a":"Non. Contrairement à la radiographie ou au scanner, l''IRM n''utilise pas de rayonnements ionisants."}]', ARRAY['Résonance magnétique','IRM']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Société française de radiologie","url":"https://www.sfrnet.org","publisher":"SFR"}]', 'التصوير بالرنين المغناطيسي (IRM)', 'ينتج التصوير بالرنين المغناطيسي صوراً دقيقة جداً للأعضاء والأنسجة الرخوة باستخدام مجال مغناطيسي، دون أشعة سينية. فحص غير مؤلم يستكشف الدماغ والنخاع والمفاصل والبطن، ويستغرق عادة من 15 إلى 45 دقيقة.', 'استكشاف الدماغ والنخاع الشوكي
تقييم المفاصل (الركبة، الكتف، العمود الفقري)
البحث عن ورم أو التهاب أو إصابة في الأنسجة الرخوة', 'تستلقي على طاولة تنزلق داخل نفق مفتوح من الطرفين
يجب البقاء دون حركة تماماً أثناء التصوير
يصدر الجهاز أصواتاً متكررة (يُقدَّم سماعات عازلة)
قد تُحقن مادة تباين أحياناً', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية ووفق التسعيرة الوطنية المرجعية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7950004eghlbnkvvupq', 'Mammographie', 'mammographie', 'imagerie', 'La mammographie est une radiographie des seins à faible dose de rayons X, utilisée pour dépister et diagnostiquer les anomalies mammaires, dont le cancer du sein. Rapide (15 minutes environ), elle est recommandée en dépistage à partir de 40-50 ans ou en cas de symptôme.', 'Dépistage du cancer du sein
Bilan d''une grosseur, d''une douleur ou d''un écoulement
Surveillance après un traitement mammaire', 'Le sein est comprimé quelques secondes entre deux plaques pour obtenir un cliché net
Plusieurs images de chaque sein sont prises
Une échographie mammaire complète souvent l''examen', 'Réaliser l''examen de préférence en première partie du cycle (seins moins sensibles).
Ne pas appliquer de déodorant, talc ou crème sur la poitrine le jour de l''examen.', 'Grossesse (à signaler)
Inconfort lié à la compression, généralement bref', 15, 300, 700, 'Prise en charge partielle par l''AMO/CNSS ; dépistage parfois pris en charge dans le cadre de programmes dédiés.', '[{"q":"La mammographie est-elle douloureuse ?","a":"La compression du sein peut être inconfortable quelques secondes, mais elle est nécessaire pour un cliché de qualité et reste brève."},{"q":"À partir de quel âge faire une mammographie ?","a":"Le dépistage est généralement recommandé à partir de 40 à 50 ans, plus tôt en cas d''antécédents familiaux. Demandez conseil à votre médecin."}]', ARRAY['Radiographie mammaire']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تصوير الثدي الشعاعي (الماموغرافيا)', 'تصوير الثدي الشعاعي فحص بأشعة سينية منخفضة الجرعة للثديين، يُستعمل لكشف وتشخيص تشوهات الثدي ومنها سرطان الثدي. سريع (نحو 15 دقيقة) ويُنصح به للكشف المبكر ابتداءً من 40-50 سنة أو عند وجود عرَض.', 'الكشف المبكر عن سرطان الثدي
تقييم كتلة أو ألم أو إفراز
المراقبة بعد علاج الثدي', 'يُضغط الثدي بضع ثوانٍ بين لوحتين للحصول على صورة واضحة
تُلتقط عدة صور لكل ثدي
غالباً ما يُكمَّل الفحص بتصوير بالصدى', NULL, NULL, 'تعويض جزئي من AMO/CNSS؛ قد يُغطى الكشف المبكر ضمن برامج مخصصة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z8s000by4hled1nf12k', 'Ostéodensitométrie (densité osseuse)', 'densitometrie-osseuse', 'imagerie', 'L''ostéodensitométrie mesure la densité des os grâce à de très faibles doses de rayons X, surtout au niveau de la hanche et de la colonne. Indolore et rapide, elle dépiste l''ostéoporose et évalue le risque de fracture, notamment après la ménopause.', 'Dépistage de l''ostéoporose
Bilan après une fracture survenue sans choc important
Suivi après la ménopause ou sous corticoïdes au long cours
Évaluation du risque de fracture', 'Vous êtes allongé sur une table, habillé
Un bras mobile passe au-dessus de la hanche et de la colonne
L''examen ne dure que quelques minutes', 'Éviter les compléments de calcium le jour de l''examen. Retirer les objets métalliques.', 'Grossesse (à signaler). Dose de rayons X très faible.', 15, 300, 700, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"L''examen est-il irradiant ?","a":"La dose de rayons X est très faible, bien inférieure à celle d''une radiographie standard."},{"q":"Qui devrait faire une ostéodensitométrie ?","a":"Notamment les femmes après la ménopause, les personnes sous corticoïdes prolongés ou après une fracture sans choc important."}]', ARRAY['DMO','Densitométrie','Densité osseuse']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'قياس كثافة العظام', 'يقيس فحص كثافة العظام صلابة العظم بجرعات منخفضة جداً من الأشعة، خاصة في الورك والعمود الفقري. غير مؤلم وسريع، ويكشف هشاشة العظام ويقيّم خطر الكسر، لا سيما بعد سن اليأس.', 'كشف هشاشة العظام
تقييم بعد كسر دون صدمة قوية
متابعة بعد سن اليأس أو تحت الكورتيزون المطوّل
تقييم خطر الكسر', 'تستلقي على طاولة وأنت مرتدٍ ملابسك
يمرّ ذراع متحرك فوق الورك والعمود الفقري
لا يستغرق الفحص سوى دقائق قليلة', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z8n000ay4hl424i23qn', 'Polysomnographie (étude du sommeil)', 'polysomnographie', 'exploration', 'La polysomnographie enregistre le sommeil sur une nuit complète : respiration, oxygénation, activité cérébrale, cardiaque et musculaire. Elle diagnostique notamment le syndrome d''apnées du sommeil, les insomnies complexes et d''autres troubles du sommeil. Elle se fait en laboratoire ou parfois à domicile.', 'Suspicion d''apnées du sommeil (ronflements, somnolence)
Insomnie complexe ou sommeil non réparateur
Mouvements anormaux pendant le sommeil
Somnolence excessive dans la journée', 'Des capteurs sont posés sur le corps en début de soirée
Vous dormez une nuit complète pendant l''enregistrement
Les données sont analysées par un spécialiste du sommeil', 'Éviter la caféine et la sieste le jour de l''examen. Cheveux propres et secs.', 'Examen non invasif et sans danger.', NULL, 1500, 4000, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Vais-je réussir à dormir avec les capteurs ?","a":"La plupart des gens y parviennent. Les capteurs sont indolores et une nuit d''enregistrement suffit généralement."},{"q":"Peut-on le faire à domicile ?","a":"Une version simplifiée (polygraphie) peut se faire à domicile ; la polysomnographie complète se réalise le plus souvent en laboratoire."}]', ARRAY['Enregistrement du sommeil','PSG']::text[], (SELECT id FROM specialties WHERE slug='pathologie-du-sommeil-et-de-la-vigilance'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تخطيط النوم الشامل', 'يسجّل تخطيط النوم الشامل النوم طوال ليلة كاملة: التنفس والأكسجة ونشاط الدماغ والقلب والعضلات. يشخّص خاصةً متلازمة انقطاع النفس النومي والأرق المعقّد واضطرابات نوم أخرى. يُجرى في مختبر أو أحياناً في المنزل.', 'اشتباه بانقطاع النفس النومي (شخير، نعاس)
أرق معقّد أو نوم غير مريح
حركات غير طبيعية أثناء النوم
نعاس نهاري مفرط', 'تُوضع مجسّات على الجسم مساءً
تنام ليلة كاملة أثناء التسجيل
يحلّل البيانات مختص في النوم', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z7x0006y4hl5272fq06', 'Ponction lombaire', 'ponction-lombaire', 'exploration', 'La ponction lombaire prélève un peu de liquide céphalo-rachidien dans le bas du dos, à l''aide d''une fine aiguille. Elle aide à diagnostiquer une méningite, une hémorragie ou certaines maladies neurologiques, et permet parfois d''administrer un traitement. Elle est réalisée sous anesthésie locale.', 'Suspicion de méningite ou d''encéphalite
Bilan de certaines maladies neurologiques
Recherche d''une hémorragie méningée
Analyse du liquide céphalo-rachidien', 'Vous êtes assis ou allongé, le dos courbé
Après anesthésie locale, une fine aiguille prélève le liquide dans le bas du dos
Un temps de repos est conseillé ensuite', 'Signaler un traitement anticoagulant. Un bilan de coagulation est parfois nécessaire.', 'Troubles de la coagulation
Maux de tête possibles après l''examen (repos, hydratation)', 20, 300, 800, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"La ponction lombaire est-elle dangereuse pour la moelle ?","a":"Non : elle est réalisée sous les vertèbres où se termine la moelle épinière, dans une zone sans danger pour elle."},{"q":"Aurai-je mal à la tête après ?","a":"Des maux de tête peuvent survenir. Le repos et une bonne hydratation aident à les prévenir et à les soulager."}]', ARRAY['PL']::text[], (SELECT id FROM specialties WHERE slug='neurologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'البزل القطني', 'يأخذ البزل القطني قليلاً من السائل الدماغي الشوكي من أسفل الظهر بواسطة إبرة دقيقة. يساعد على تشخيص التهاب السحايا أو نزيف أو بعض الأمراض العصبية، وقد يتيح إعطاء علاج. يُجرى تحت تخدير موضعي.', 'اشتباه بالتهاب السحايا أو الدماغ
تقييم بعض الأمراض العصبية
البحث عن نزيف سحائي
تحليل السائل الدماغي الشوكي', 'تكون جالساً أو مستلقياً مع تقوّس الظهر
بعد تخدير موضعي تأخذ إبرة دقيقة السائل من أسفل الظهر
يُنصح بالراحة بعد ذلك', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei79w0007eghl838q2q6v', 'Prise de sang (bilan sanguin)', 'prise-de-sang', 'biologie', 'La prise de sang consiste à prélever un échantillon de sang, généralement au pli du coude, pour l''analyser en laboratoire. Elle permet d''évaluer de nombreux paramètres (glycémie, cholestérol, numération, fonction rénale ou hépatique) et de dépister ou suivre de nombreuses maladies.', 'Bilan de santé général
Dépistage du diabète, du cholestérol, de l''anémie
Évaluation des fonctions rénale et hépatique
Suivi d''un traitement ou d''une maladie chronique', 'Un garrot est posé sur le bras pour repérer une veine
Le préleveur désinfecte la peau puis prélève le sang dans un ou plusieurs tubes
Le prélèvement dure moins de cinq minutes', 'Jeûne de 8 à 12 heures pour certains dosages (glycémie, cholestérol) — vérifiez avec le laboratoire.
Apporter l''ordonnance et la liste de vos traitements.', 'Signaler un traitement anticoagulant ou un malaise habituel aux prises de sang.', 10, 150, 600, 'Prise en charge partielle par l''AMO/CNSS selon les analyses prescrites.', '[{"q":"Faut-il toujours être à jeun ?","a":"Non, seulement pour certains dosages comme la glycémie ou le bilan lipidique. Votre médecin ou le laboratoire vous le précisera."},{"q":"Combien de temps pour avoir les résultats ?","a":"La plupart des résultats courants sont disponibles en quelques heures à 48 heures selon les analyses."}]', ARRAY['Bilan sanguin','Analyse de sang','Prélèvement sanguin']::text[], (SELECT id FROM specialties WHERE slug='biologie-medicale'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'تحليل الدم', 'يتمثّل تحليل الدم في أخذ عينة دم، غالباً من ثنية المرفق، لتحليلها في المختبر. يتيح تقييم عدة مؤشرات (السكر، الكوليسترول، تعداد الدم، وظائف الكلى والكبد) وكشف أو متابعة أمراض عديدة.', 'تقييم صحي عام
كشف السكري والكوليسترول وفقر الدم
تقييم وظائف الكلى والكبد
متابعة علاج أو مرض مزمن', 'تُوضع رباطة على الذراع لتحديد الوريد
يُطهّر الجلد ثم يُؤخذ الدم في أنبوب أو أكثر
يستغرق السحب أقل من خمس دقائق', NULL, NULL, 'تعويض جزئي من AMO/CNSS حسب التحاليل الموصوفة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei78n0002eghl9mr7hum6', 'Radiographie', 'radiographie', 'imagerie', 'La radiographie est un examen d''imagerie rapide et courant qui utilise de faibles doses de rayons X pour visualiser surtout les os et les poumons. Indolore et de quelques minutes, elle sert notamment à détecter fractures, pneumonies ou anomalies thoraciques.', 'Recherche de fracture ou de luxation
Bilan pulmonaire (pneumonie, tuberculose)
Contrôle articulaire et osseux
Bilan avant chirurgie', 'Vous êtes debout, assis ou allongé selon la zone à examiner
Un cliché est pris en quelques secondes, il faut rester immobile
Plusieurs incidences (angles) peuvent être réalisées', 'Aucune préparation particulière dans la plupart des cas.
Retirer les objets métalliques de la zone examinée.', 'Grossesse (à signaler ; protection ou report selon l''urgence)', 10, 100, 400, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"La radiographie est-elle dangereuse ?","a":"La dose de rayons X d''une radiographie standard est faible et le bénéfice diagnostique dépasse largement le risque. La grossesse doit toutefois être signalée."},{"q":"Faut-il être à jeun ?","a":"Non, aucune préparation ni jeûne n''est nécessaire pour une radiographie standard."}]', ARRAY['Radio','Rayons X']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Société française de radiologie","url":"https://www.sfrnet.org","publisher":"SFR"}]', 'التصوير بالأشعة السينية', 'التصوير بالأشعة السينية فحص سريع وشائع يستخدم جرعات منخفضة من الأشعة لرؤية العظام والرئتين خاصة. غير مؤلم ويستغرق دقائق، ويُستعمل لكشف الكسور والالتهاب الرئوي أو تشوهات الصدر.', 'البحث عن كسر أو خلع
تقييم رئوي (التهاب رئوي، السل)
فحص المفاصل والعظام
تقييم قبل الجراحة', 'تكون واقفاً أو جالساً أو مستلقياً حسب المنطقة
تُلتقط الصورة في ثوانٍ ويجب البقاء دون حركة
قد تُؤخذ عدة زوايا', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei78f0001eghlgy2laiyx', 'Scanner (tomodensitométrie, TDM)', 'scanner', 'imagerie', 'Le scanner utilise des rayons X pour produire des images en coupes précises du corps. Rapide (quelques minutes), il est très utile en urgence pour explorer le thorax, l''abdomen, le cerveau ou les os. Un produit de contraste iodé est souvent injecté.', 'Bilan en urgence (traumatisme, hémorragie, embolie pulmonaire)
Exploration du thorax et de l''abdomen
Recherche et suivi de cancers
Bilan osseux détaillé', 'Vous êtes allongé sur une table qui traverse un anneau (l''examen n''est pas fermé comme l''IRM)
L''acquisition ne dure que quelques secondes à quelques minutes
Un produit de contraste iodé peut être injecté dans une veine du bras', 'Jeûne de 2 à 4 heures en cas d''injection de produit de contraste.
Apporter un bilan rénal récent (créatinine) si demandé.
Signaler toute allergie connue à l''iode.', 'Grossesse (les rayons X sont à éviter, sauf urgence)
Allergie au produit de contraste iodé
Insuffisance rénale (adaptation ou report de l''injection)', 15, 800, 2500, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Quelle différence entre un scanner et une IRM ?","a":"Le scanner utilise des rayons X et est très rapide, idéal en urgence et pour les os et le thorax. L''IRM, sans rayons X, est plus précise pour les tissus mous (cerveau, articulations)."},{"q":"Le produit de contraste est-il dangereux ?","a":"Il est généralement bien toléré. De rares réactions allergiques sont possibles ; signalez toute allergie à l''iode et vos antécédents rénaux."}]', ARRAY['TDM','CT-scan','Tomodensitométrie']::text[], (SELECT id FROM specialties WHERE slug='radiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Société française de radiologie","url":"https://www.sfrnet.org","publisher":"SFR"}]', 'السكانير (التصوير المقطعي المحوسب)', 'يستخدم السكانير الأشعة السينية لإنتاج صور مقطعية دقيقة للجسم. سريع (بضع دقائق) ومفيد جداً في الحالات الطارئة لاستكشاف الصدر والبطن والدماغ والعظام. غالباً ما تُحقن مادة تباين يودية.', 'تقييم في الحالات الطارئة (رضّ، نزيف، انصمام رئوي)
استكشاف الصدر والبطن
البحث عن السرطانات ومتابعتها
تقييم عظمي مفصّل', 'تستلقي على طاولة تعبر حلقة (الفحص ليس مغلقاً كالرنين)
لا يستغرق التصوير سوى ثوانٍ إلى دقائق قليلة
قد تُحقن مادة تباين يودية في وريد الذراع', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z9x000hy4hlagsqhmoc', 'Scintigraphie', 'scintigraphie', 'imagerie', 'La scintigraphie utilise un produit faiblement radioactif (traceur) injecté puis détecté par une caméra spéciale, pour étudier le fonctionnement d''un organe : os, thyroïde, cœur ou reins. Elle révèle des anomalies non visibles sur d''autres examens et se réalise en médecine nucléaire.', 'Recherche de métastases ou d''anomalies osseuses
Bilan de la thyroïde
Étude de la perfusion du cœur
Évaluation de la fonction rénale', 'Un traceur faiblement radioactif est injecté
Un temps d''attente permet sa fixation sur l''organe
Une caméra prend les images ; l''examen est indolore', 'Boire de l''eau et uriner régulièrement après l''examen pour éliminer le traceur. Consignes spécifiques selon l''organe étudié.', 'Grossesse et allaitement (à signaler)
Éviter le contact rapproché prolongé avec de jeunes enfants pendant quelques heures', 30, 1500, 4000, 'Acte de médecine nucléaire : prise en charge partielle par l''AMO/CNSS sur prescription.', '[{"q":"La radioactivité est-elle dangereuse ?","a":"La dose du traceur est faible et éliminée rapidement. Les précautions concernent surtout la grossesse et le contact avec les jeunes enfants."},{"q":"L''examen est-il douloureux ?","a":"Non, en dehors de la piqûre d''injection du traceur. Le reste de l''examen est indolore."}]', ARRAY['Scintigraphie osseuse','Scintigraphie thyroïdienne']::text[], (SELECT id FROM specialties WHERE slug='medecine-nucleaire'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'التصوير الومضاني (السينتيغرافيا)', 'يستخدم التصوير الومضاني مادة ضعيفة الإشعاع (كاشف) تُحقن ثم تلتقطها كاميرا خاصة لدراسة عمل عضو: العظام أو الغدة الدرقية أو القلب أو الكلى. يكشف شذوذات غير مرئية في فحوصات أخرى، ويُجرى في الطب النووي.', 'البحث عن نقائل أو شذوذات عظمية
تقييم الغدة الدرقية
دراسة تروية القلب
تقييم وظيفة الكلى', 'يُحقن كاشف ضعيف الإشعاع
فترة انتظار تتيح تثبيته على العضو
تلتقط الكاميرا الصور؛ والفحص غير مؤلم', NULL, NULL, 'إجراء في الطب النووي: تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z8h0009y4hl3n7lxd35', 'Spirométrie (exploration du souffle)', 'spirometrie', 'exploration', 'La spirométrie mesure le souffle : le volume et la vitesse de l''air que vous expirez dans un embout. Indolore, elle aide à diagnostiquer et suivre l''asthme et la BPCO, et à évaluer un essoufflement. L''examen dure environ 20 minutes.', 'Diagnostic et suivi de l''asthme
Bilan de la BPCO (bronchite chronique)
Évaluation d''un essoufflement ou d''une toux chronique
Bilan avant chirurgie ou en médecine du travail', 'Vous soufflez fort et longuement dans un embout, le nez pincé
Plusieurs mesures sont réalisées pour la fiabilité
Un médicament bronchodilatateur est parfois testé', 'Éviter de fumer et l''effort intense avant l''examen. Certains inhalateurs sont à suspendre (selon consignes).', 'Effort respiratoire pouvant être fatigant ; rares contre-indications à évaluer.', 20, 200, 500, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"La spirométrie est-elle fatigante ?","a":"L''effort de souffle peut être un peu fatigant, mais chaque manœuvre est brève et l''examen reste bien toléré."},{"q":"À quoi sert-elle dans l''asthme ?","a":"Elle mesure le degré d''obstruction des bronches et la réponse aux bronchodilatateurs, utile pour diagnostiquer et suivre l''asthme."}]', ARRAY['EFR','Exploration fonctionnelle respiratoire']::text[], (SELECT id FROM specialties WHERE slug='pneumo-phtisiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'قياس التنفس', 'يقيس قياس التنفس النَّفَس: حجم وسرعة الهواء الذي تُخرجه في قطعة فموية. غير مؤلم، ويساعد على تشخيص ومتابعة الربو والانسداد الرئوي المزمن وتقييم ضيق التنفس. يستغرق نحو 20 دقيقة.', 'تشخيص ومتابعة الربو
تقييم الانسداد الرئوي المزمن
تقييم ضيق التنفس أو سعال مزمن
تقييم قبل الجراحة أو في طب الشغل', 'تنفخ بقوة ولمدة طويلة في قطعة فموية مع سدّ الأنف
تُجرى عدة قياسات لضمان الدقة
قد يُختبَر دواء موسّع للقصبات', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0za2000iy4hlagu0klnu', 'TEP-scan (PET-scan)', 'tep-scan', 'imagerie', 'Le TEP-scan (PET-scan) associe une caméra à un traceur faiblement radioactif pour repérer les zones de forte activité cellulaire. Très utile en cancérologie, il aide à localiser une tumeur, évaluer son extension ou la réponse au traitement. Il se réalise en médecine nucléaire.', 'Bilan d''extension d''un cancer
Évaluation de la réponse à un traitement
Recherche d''une récidive
Caractérisation de certaines lésions', 'Un traceur est injecté, suivi d''un temps de repos d''environ une heure
Vous passez ensuite dans la caméra TEP couplée à un scanner
L''examen complet est indolore', 'Jeûne de plusieurs heures ; éviter l''effort la veille. Bien s''hydrater après l''examen.', 'Grossesse et allaitement (à signaler)
Diabète (glycémie à contrôler avant l''examen)', 30, 6000, 12000, 'Acte de médecine nucléaire coûteux : prise en charge partielle par l''AMO/CNSS sur prescription, souvent en milieu hospitalier.', '[{"q":"Pourquoi attendre après l''injection ?","a":"Le traceur a besoin de temps (environ une heure) pour se répartir dans le corps et se fixer sur les zones actives avant l''acquisition des images."},{"q":"Faut-il être à jeun ?","a":"Oui, un jeûne de plusieurs heures est nécessaire, et la glycémie est contrôlée, surtout en cas de diabète."}]', ARRAY['PET-scan','Tomographie par émission de positons']::text[], (SELECT id FROM specialties WHERE slug='medecine-nucleaire'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'التصوير المقطعي بالإصدار البوزيتروني (PET)', 'يجمع الـPET بين كاميرا وكاشف ضعيف الإشعاع لتحديد مناطق النشاط الخلوي المرتفع. مفيد جداً في علم الأورام، ويساعد على تحديد ورم وتقييم انتشاره أو استجابته للعلاج. يُجرى في الطب النووي.', 'تقييم انتشار السرطان
تقييم الاستجابة للعلاج
البحث عن نكس
توصيف بعض الآفات', 'يُحقن كاشف يليه راحة نحو ساعة
ثم تمرّ في كاميرا PET المقترنة بالسكانير
الفحص كاملاً غير مؤلم', NULL, NULL, 'إجراء مكلف في الطب النووي: تعويض جزئي من AMO/CNSS بوصفة، غالباً في وسط استشفائي.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z9s000gy4hl35apbrc7', 'Test de grossesse sanguin (bêta-HCG)', 'test-grossesse', 'biologie', 'Le test de grossesse sanguin dose l''hormone bêta-HCG dans le sang. Plus précoce et fiable que le test urinaire, il confirme une grossesse et permet d''en suivre l''évolution initiale. Le résultat est en général disponible le jour même.', 'Confirmation d''une grossesse
Retard de règles
Suivi précoce du début de grossesse
Bilan en cas de douleurs ou de saignements en début de grossesse', 'Une simple prise de sang est réalisée
Le taux de bêta-HCG est dosé au laboratoire
Un contrôle à 48 h peut être demandé pour suivre l''évolution', 'Aucune préparation ni jeûne nécessaire.', 'Aucune contre-indication.', 5, 80, 200, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Est-il plus fiable que le test urinaire ?","a":"Oui, le test sanguin est plus précoce et plus précis ; il quantifie l''hormone et permet de suivre l''évolution du taux."},{"q":"Faut-il être à jeun ?","a":"Non, aucun jeûne n''est nécessaire pour un dosage de bêta-HCG."}]', ARRAY['Bêta-HCG','Test de grossesse par prise de sang']::text[], (SELECT id FROM specialties WHERE slug='biologie-medicale'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'اختبار الحمل الدموي (بيتا-HCG)', 'يقيس اختبار الحمل الدموي هرمون بيتا-HCG في الدم. أبكر وأكثر موثوقية من اختبار البول، ويؤكد الحمل ويتيح متابعة بدايته. تتوفّر النتيجة عادة في اليوم نفسه.', 'تأكيد الحمل
تأخّر الدورة
متابعة مبكرة لبداية الحمل
تقييم عند ألم أو نزيف في بداية الحمل', 'يُجرى سحب دم بسيط
يُقاس مستوى بيتا-HCG في المختبر
قد يُطلب فحص بعد 48 ساعة لمتابعة التطور', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtf0z9g000ey4hlk54mx93j', 'Tests allergologiques (prick-tests)', 'test-allergie', 'exploration', 'Les tests allergologiques cutanés (prick-tests) recherchent une allergie en déposant de petites gouttes d''allergènes sur la peau, légèrement piquée. La réaction locale est lue après 15 à 20 minutes. Ils identifient les allergies aux pollens, acariens, aliments ou poils d''animaux.', 'Rhinite ou conjonctivite allergique
Asthme allergique
Suspicion d''allergie alimentaire
Bilan d''urticaire ou d''eczéma', 'De petites gouttes d''allergènes sont déposées sur l''avant-bras ou le dos
La peau est légèrement piquée à travers chaque goutte
La réaction (petite papule) est mesurée après 15 à 20 minutes', 'Arrêter les antihistaminiques quelques jours avant (selon les consignes du médecin).', 'Réactions locales (démangeaisons) habituelles ; réaction générale très rare, surveillée sur place.', 30, 300, 800, 'Prise en charge partielle par l''AMO/CNSS sur prescription médicale.', '[{"q":"Les prick-tests font-ils mal ?","a":"La petite piqûre est superficielle et peu douloureuse. Une démangeaison locale peut apparaître en cas de réaction."},{"q":"Faut-il arrêter des médicaments avant ?","a":"Oui, les antihistaminiques doivent souvent être arrêtés quelques jours avant, car ils faussent les résultats. Suivez les consignes du médecin."}]', ARRAY['Prick-tests','Tests cutanés allergiques']::text[], (SELECT id FROM specialties WHERE slug='allergologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'اختبارات الحساسية الجلدية', 'تبحث اختبارات الحساسية الجلدية عن الحساسية بوضع قطرات صغيرة من المواد المسببة على الجلد المشروط قليلاً. تُقرأ ردة الفعل الموضعية بعد 15 إلى 20 دقيقة. تحدّد الحساسية تجاه اللقاح وعث الغبار والأطعمة أو وبر الحيوانات.', 'التهاب أنف أو ملتحمة تحسسي
ربو تحسسي
اشتباه بحساسية غذائية
تقييم شرى أو إكزيما', 'تُوضع قطرات صغيرة من المواد المسببة على الساعد أو الظهر
يُشرَط الجلد قليلاً عبر كل قطرة
تُقاس ردة الفعل بعد 15 إلى 20 دقيقة', NULL, NULL, 'تعويض جزئي من AMO/CNSS بوصفة طبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now())
ON CONFLICT (slug) DO NOTHING;


-- ─── Traitements ───
INSERT INTO treatments ("id", "name", "slug", "category", "shortAnswer", "options", "duration", "sideEffects", "redFlags", "whenToConsult", "faqJson", "synonyms", "specialtyId", "relatedSlugs", "glossarySlugs", "sources", "nameAr", "shortAnswerAr", "optionsAr", "durationAr", "sideEffectsAr", "redFlagsAr", "whenToConsultAr", "faqJsonAr", "sourcesAr", "arReviewedAt", "reviewedAt", "status", "views", "createdAt", "updatedAt")
VALUES
  ('cmrtei7d2000jeghlyibxjlry', 'Traitement de l''acné', 'traitement-acne', 'medicamenteux', 'Le traitement de l''acné dépend de sa sévérité : soins locaux adaptés (rétinoïdes, peroxyde de benzoyle) pour les formes légères, traitements par voie orale (antibiotiques, isotrétinoïne) pour les formes plus sévères. Une routine douce et régulière de la peau est essentielle.', 'Soins locaux : rétinoïdes topiques, peroxyde de benzoyle, antibiotiques locaux
Traitements oraux (antibiotiques, isotrétinoïne) pour les formes sévères
Routine de nettoyage douce, non comédogène
Avis dermatologique pour adapter le traitement et prévenir les cicatrices', 'L''acné évolue souvent sur plusieurs années à l''adolescence. Les traitements demandent de la patience : plusieurs semaines avant les premiers résultats, avec un suivi pour ajuster la stratégie.', 'Sécheresse et irritation cutanée avec les traitements locaux
Effets spécifiques de l''isotrétinoïne nécessitant un suivi médical strict', 'Acné sévère, nodulaire ou laissant des cicatrices
Retentissement psychologique important
Acné résistante aux soins locaux bien conduits', 'Consultez un dermatologue en cas d''acné sévère, cicatricielle, résistante ou mal vécue, pour un traitement adapté.', '[{"q":"L''alimentation joue-t-elle un rôle dans l''acné ?","a":"Son rôle est débattu et modeste. Certains aliments à index glycémique élevé pourraient aggraver l''acné chez certaines personnes, mais le traitement repose surtout sur les soins dermatologiques."},{"q":"Faut-il percer les boutons ?","a":"Non, cela augmente le risque d''infection et de cicatrices. Mieux vaut un traitement adapté et une routine douce."}]', ARRAY['Acné juvénile','Boutons']::text[], (SELECT id FROM specialties WHERE slug='dermatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج حب الشباب', 'يعتمد علاج حب الشباب على شدته: علاجات موضعية مناسبة للأشكال الخفيفة، وعلاجات فموية للأشكال الأشد. روتين لطيف ومنتظم للبشرة أساسي.', 'علاجات موضعية: ريتينويدات، بيروكسيد البنزويل، مضادات حيوية موضعية
علاجات فموية للأشكال الشديدة
روتين تنظيف لطيف
استشارة طبيب جلد لتكييف العلاج والوقاية من الندبات', NULL, NULL, NULL, 'استشر طبيب أمراض جلدية عند حب شباب شديد أو مُندِّب أو مقاوم أو مؤثر نفسياً.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ibz000jkshlav7wwgkl', 'Traitement de l''anémie par manque de fer', 'traitement-anemie-ferriprive', 'medicamenteux', 'Le traitement de l''anémie par carence en fer repose sur la supplémentation en fer (le plus souvent par comprimés) et, surtout, sur la recherche et le traitement de la cause du manque de fer (règles abondantes, saignement digestif, alimentation). Le fer se prend plusieurs mois pour reconstituer les réserves.', 'Supplémentation en fer (comprimés, parfois en intraveineux)
Recherche et traitement de la cause du manque de fer
Alimentation riche en fer (viande, légumineuses, légumes verts)
Contrôle sanguin pour suivre la correction', 'Le fer se prend en général plusieurs mois pour corriger l''anémie et reconstituer les réserves, avec un contrôle sanguin de l''efficacité.', 'Troubles digestifs et selles foncées avec le fer oral
Meilleure tolérance en adaptant la prise (avis médical)', 'Fatigue intense, essoufflement ou pâleur marquée
Saignements abondants (règles, digestifs)
Anémie qui ne se corrige pas malgré le traitement', 'Consultez en cas de fatigue persistante avec pâleur ou essoufflement, de saignements abondants, ou si l''anémie ne se corrige pas.', '[{"q":"Pourquoi chercher la cause d''un manque de fer ?","a":"Parce que l''anémie n''est qu''un symptôme : il faut identifier l''origine (règles abondantes, saignement digestif…) pour la traiter et éviter la récidive."},{"q":"Combien de temps prendre le fer ?","a":"En général plusieurs mois, même une fois l''anémie corrigée, afin de reconstituer les réserves en fer de l''organisme."}]', ARRAY['Carence en fer','Anémie ferriprive','Manque de fer']::text[], (SELECT id FROM specialties WHERE slug='hematologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج فقر الدم بعوز الحديد', 'يعتمد علاج فقر الدم بعوز الحديد على تعويض الحديد (غالباً بأقراص)، وقبل كل شيء البحث عن سبب النقص ومعالجته (دورة غزيرة، نزيف هضمي، تغذية). يُؤخذ الحديد عدة أشهر لإعادة بناء المخزون.', 'تعويض الحديد (أقراص، وأحياناً وريدياً)
البحث عن سبب نقص الحديد ومعالجته
تغذية غنية بالحديد (لحوم، بقول، خضر)
مراقبة دموية لمتابعة التصحيح', NULL, NULL, NULL, 'استشر عند تعب مستمر مع شحوب أو ضيق تنفس، أو نزيف غزير، أو إذا لم يتحسّن فقر الدم.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iat000bkshlc1ambvop', 'Traitement de l''angine', 'traitement-angine', 'medicamenteux', 'La plupart des angines sont virales et guérissent seules avec des antalgiques ; les antibiotiques ne sont utiles que pour les angines bactériennes (à streptocoque), identifiées par un test rapide. Boire, se reposer et soulager la douleur suffisent souvent en quelques jours.', 'Antalgiques et antipyrétiques (paracétamol)
Hydratation, repos, boissons apaisantes
Test rapide d''orientation diagnostique (angine à streptocoque)
Antibiotiques uniquement si angine bactérienne confirmée', 'Une angine virale guérit en quelques jours. Une angine bactérienne traitée par antibiotiques s''améliore rapidement ; le traitement doit être mené à terme.', 'Effets digestifs des antibiotiques quand ils sont nécessaires', 'Difficulté à avaler sa salive ou à respirer
Gonflement important du cou, voix étouffée
Fièvre élevée persistante malgré le traitement', 'Consultez en cas de forte fièvre, de difficulté à avaler ou à respirer, ou d''angine qui ne s''améliore pas ; un test permet de décider des antibiotiques.', '[{"q":"L''angine nécessite-t-elle toujours des antibiotiques ?","a":"Non : la plupart sont virales. Un test rapide identifie les angines à streptocoque, seules à justifier des antibiotiques."},{"q":"Combien de temps dure une angine ?","a":"Le plus souvent quelques jours. Consultez si la fièvre persiste ou si avaler ou respirer devient difficile."}]', ARRAY['Amygdalite','Mal de gorge']::text[], (SELECT id FROM specialties WHERE slug='oto-rhino-laryngologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب اللوزتين (الحلق)', 'معظم التهابات الحلق فيروسية وتُشفى وحدها بالمسكّنات؛ لا تفيد المضادات الحيوية إلا في الالتهاب الجرثومي (بالمكورات العقدية) الذي يحدّده اختبار سريع. الشرب والراحة وتخفيف الألم تكفي غالباً في أيام.', 'مسكّنات وخافضات حرارة (الباراسيتامول)
ترطيب وراحة ومشروبات مهدّئة
اختبار سريع لتوجيه التشخيص
مضادات حيوية فقط عند تأكيد الالتهاب الجرثومي', NULL, NULL, NULL, 'استشر عند حمى شديدة أو صعوبة في البلع أو التنفس، أو التهاب لا يتحسّن؛ يساعد الاختبار على تقرير المضادات الحيوية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i8m0000kshlhtl7224d', 'Traitement de l''anxiété', 'traitement-anxiete', 'medicamenteux', 'Le traitement de l''anxiété associe une psychothérapie (notamment cognitivo-comportementale), des techniques de gestion du stress et, si nécessaire, des médicaments. Une bonne hygiène de vie (sommeil, activité physique, réduction des excitants) complète la prise en charge, adaptée à chaque personne.', 'Psychothérapie, en particulier thérapies cognitivo-comportementales
Techniques de relaxation et de gestion du stress
Hygiène de vie : sommeil régulier, activité physique, limitation de la caféine
Médicaments (antidépresseurs, anxiolytiques en cure courte) si nécessaire', 'La prise en charge s''inscrit dans la durée : la psychothérapie s''étale sur plusieurs semaines à mois ; les anxiolytiques ne se prennent qu''en cures courtes pour éviter la dépendance.', 'Somnolence et risque de dépendance avec les anxiolytiques (usage court)
Effets transitoires en début de traitement antidépresseur', 'Crises d''angoisse invalidantes et répétées
Idées noires ou pensées suicidaires
Retentissement majeur sur le travail et la vie quotidienne', 'Consultez si l''anxiété est persistante, envahissante ou retentit sur votre quotidien, et en urgence en cas d''idées suicidaires.', '[{"q":"Les anxiolytiques rendent-ils dépendant ?","a":"Certains (benzodiazépines) peuvent créer une dépendance : ils se prescrivent sur une courte durée. La psychothérapie reste le traitement de fond."},{"q":"La psychothérapie est-elle efficace ?","a":"Oui, les thérapies cognitivo-comportementales ont fait la preuve de leur efficacité dans les troubles anxieux, seules ou avec un traitement médicamenteux."}]', ARRAY['Troubles anxieux','Anxiété généralisée']::text[], (SELECT id FROM specialties WHERE slug='psychiatrie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج القلق', 'يجمع علاج القلق بين العلاج النفسي (خاصة المعرفي السلوكي)، وتقنيات إدارة التوتر، وعند الحاجة أدوية. يكمّل نمط حياة سليم (نوم، نشاط بدني، تقليل المنبهات) الرعاية المكيَّفة مع كل شخص.', 'العلاج النفسي، خاصة المعرفي السلوكي
تقنيات الاسترخاء وإدارة التوتر
نمط حياة سليم: نوم منتظم، نشاط بدني، تقليل الكافيين
أدوية عند الحاجة', NULL, NULL, NULL, 'استشر إذا كان القلق مستمراً أو مُسيطراً أو يؤثر على حياتك اليومية، وطارئاً عند أفكار انتحارية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i980002kshlwsdruxyx', 'Traitement de l''arthrose', 'traitement-arthrose', 'medicamenteux', 'Le traitement de l''arthrose vise à soulager la douleur et à préserver la mobilité : activité physique adaptée, perte de poids, antalgiques et parfois infiltrations. La chirurgie (prothèse) est réservée aux formes évoluées. Il n''existe pas de traitement qui guérit l''arthrose, mais on la contrôle bien.', 'Activité physique adaptée et maintien de la mobilité
Perte de poids pour soulager les articulations portantes
Antalgiques et anti-inflammatoires lors des poussées
Infiltrations et kinésithérapie ; chirurgie (prothèse) si forme évoluée', 'L''arthrose est chronique et évolue lentement. La prise en charge est au long cours, centrée sur l''activité physique régulière et le contrôle de la douleur.', 'Troubles digestifs avec les anti-inflammatoires (usage limité)
Effet temporaire des infiltrations', 'Articulation rouge, chaude et très gonflée (autre cause à écarter)
Blocage articulaire ou perte de mobilité rapide
Douleur intense résistant aux traitements', 'Consultez un rhumatologue si la douleur devient invalidante, limite vos activités ou résiste aux mesures habituelles.', '[{"q":"Faut-il se reposer quand on a de l''arthrose ?","a":"Non : l''activité physique adaptée est un pilier du traitement. Le repos prolongé aggrave la raideur et la perte de mobilité."},{"q":"L''arthrose se guérit-elle ?","a":"Elle ne se guérit pas, mais la douleur et la gêne se contrôlent bien. La prothèse peut être proposée dans les formes très évoluées."}]', ARRAY['Ostéoarthrose','Usure du cartilage']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الفصال العظمي (خشونة المفاصل)', 'يهدف علاج الفصال العظمي إلى تخفيف الألم والحفاظ على الحركة: نشاط بدني مناسب، إنقاص الوزن، مسكّنات وأحياناً حقن موضعي. تُخصَّص الجراحة (المفصل الصناعي) للأشكال المتقدمة. لا يوجد علاج يشفي الخشونة لكن يمكن التحكم فيها.', 'نشاط بدني مناسب والحفاظ على الحركة
إنقاص الوزن لتخفيف الحمل على المفاصل
مسكّنات ومضادات التهاب أثناء النوبات
حقن موضعي وعلاج طبيعي؛ وجراحة عند التقدّم', NULL, NULL, NULL, 'استشر طبيب الروماتيزم إذا أصبح الألم مُعيقاً أو حدّ من نشاطك أو قاوم التدابير المعتادة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7bg000ceghlfdvah42n', 'Traitement de l''asthme', 'traitement-asthme', 'medicamenteux', 'Le traitement de l''asthme repose sur deux volets : un traitement de fond inhalé (corticoïdes) pour contrôler l''inflammation au quotidien, et un traitement de crise (bronchodilatateur à action rapide) en cas de gêne. Éviter les facteurs déclenchants est essentiel.', 'Traitement de fond : corticoïdes inhalés, quotidiens
Traitement de crise : bronchodilatateur à action rapide
Éviction des facteurs déclenchants (allergènes, tabac, pollution)
Plan d''action personnalisé et éducation à l''utilisation de l''inhalateur', 'L''asthme est une maladie chronique. Le traitement de fond se prend au long cours ; les doses sont adaptées selon le contrôle des symptômes, avec un suivi régulier.', 'Irritation de la gorge ou mycose buccale avec les corticoïdes inhalés (rincer la bouche après usage)
Tremblements ou palpitations avec les bronchodilatateurs', 'Crise d''asthme qui ne cède pas au traitement de crise
Essoufflement au repos, difficulté à parler ou lèvres bleutées
Recours de plus en plus fréquent au traitement de secours', 'Consultez rapidement si l''asthme est mal contrôlé, et appelez les secours en cas de crise sévère ne répondant pas au bronchodilatateur.', '[{"q":"Les corticoïdes inhalés sont-ils dangereux ?","a":"Aux doses inhalées, ils agissent localement dans les bronches avec très peu d''effets généraux. Ils sont la base du contrôle de l''asthme."},{"q":"Peut-on arrêter le traitement de fond quand on va bien ?","a":"Non sans avis médical : se sentir bien est souvent le résultat du traitement de fond. L''arrêter expose à une rechute."}]', ARRAY['Maladie asthmatique']::text[], (SELECT id FROM specialties WHERE slug='pneumo-phtisiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الربو', 'يعتمد علاج الربو على محورين: علاج أساسي مستنشق (كورتيكويدات) للتحكم في الالتهاب يومياً، وعلاج للنوبة (موسّع قصبي سريع) عند الضيق. تجنّب العوامل المحفزة أساسي.', 'علاج أساسي: كورتيكويدات مستنشقة يومياً
علاج النوبة: موسّع قصبي سريع
تجنّب العوامل المحفزة (مسببات الحساسية، التدخين، التلوث)
خطة عمل شخصية والتدريب على استعمال البخاخ', NULL, NULL, NULL, 'استشر بسرعة إذا كان الربو غير متحكَّم فيه، واتصل بالإسعاف عند نوبة شديدة لا تستجيب للموسّع القصبي.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7bq000deghl4hmzcu2f', 'Traitement de l''eczéma (dermatite atopique)', 'traitement-eczema', 'medicamenteux', 'Le traitement de l''eczéma repose sur l''hydratation quotidienne de la peau avec des émollients, des crèmes à la cortisone (dermocorticoïdes) lors des poussées, et l''éviction des facteurs irritants ou allergènes. L''objectif est d''espacer et de calmer les poussées.', 'Émollients : hydratation quotidienne, base du traitement
Dermocorticoïdes lors des poussées
Éviction des irritants (savons agressifs, laine) et des allergènes identifiés
Traitements spécialisés pour les formes sévères (avis dermatologique)', 'L''eczéma atopique évolue par poussées sur un fond chronique. L''hydratation est permanente ; les dermocorticoïdes s''utilisent en cures courtes lors des poussées.', 'Amincissement de la peau en cas d''usage prolongé et excessif de dermocorticoïdes
Sensation de picotement à l''application de certaines crèmes', 'Lésions suintantes, croûtes jaunâtres ou fièvre (surinfection)
Eczéma étendu résistant au traitement
Retentissement important sur le sommeil et la qualité de vie', 'Consultez un dermatologue si les poussées sont fréquentes, étendues, surinfectées ou résistantes au traitement habituel.', '[{"q":"L''eczéma est-il contagieux ?","a":"Non, l''eczéma n''est pas contagieux. C''est une maladie inflammatoire de la peau, souvent liée à un terrain atopique."},{"q":"La cortisone en crème est-elle dangereuse ?","a":"Bien utilisée, en cures courtes lors des poussées, elle est efficace et sûre. Les effets indésirables surviennent surtout en cas d''usage prolongé et non encadré."}]', ARRAY['Dermatite atopique','Eczéma atopique']::text[], (SELECT id FROM specialties WHERE slug='dermatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الإكزيما (التهاب الجلد التأتبي)', 'يعتمد علاج الإكزيما على ترطيب البشرة يومياً بالمرطبات، وكريمات الكورتيزون الموضعية أثناء النوبات، وتجنّب المهيّجات والمواد المسببة للحساسية. الهدف تباعد النوبات وتهدئتها.', 'المرطبات: ترطيب يومي، أساس العلاج
الكورتيكويدات الموضعية أثناء النوبات
تجنّب المهيّجات والمواد المسببة للحساسية
علاجات متخصصة للأشكال الشديدة', NULL, NULL, NULL, 'استشر طبيب أمراض جلدية إذا كانت النوبات متكررة أو واسعة أو متعفنة أو مقاومة للعلاج المعتاد.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ibt000ikshlk051w7eh', 'Traitement de l''excès de cholestérol', 'traitement-hypercholesterolemie', 'medicamenteux', 'Le traitement de l''excès de cholestérol repose sur une alimentation équilibrée, l''activité physique et l''arrêt du tabac ; des médicaments (statines notamment) sont ajoutés selon le risque cardiovasculaire global. L''objectif est de réduire le risque d''infarctus et d''AVC en abaissant le mauvais cholestérol (LDL).', 'Alimentation équilibrée, pauvre en graisses saturées
Activité physique régulière et arrêt du tabac
Statines et autres médicaments selon le risque cardiovasculaire
Contrôle des autres facteurs (tension, diabète, poids)', 'La prise en charge est au long cours : hygiène de vie durable et, si un médicament est indiqué, traitement prolongé avec contrôle régulier du bilan lipidique.', 'Douleurs musculaires possibles sous statines (à signaler)
Surveillance biologique selon les cas', 'Douleur thoracique ou essoufflement à l''effort
Douleurs musculaires importantes sous statine
Antécédents familiaux d''accident cardiaque précoce', 'Consultez pour évaluer votre risque cardiovasculaire global, adapter le traitement, ou en cas de douleurs musculaires sous statine.', '[{"q":"Faut-il toujours un médicament contre le cholestérol ?","a":"Non : la décision dépend du risque cardiovasculaire global, pas du seul chiffre. L''hygiène de vie est la première étape."},{"q":"Les statines sont-elles dangereuses ?","a":"Elles sont généralement bien tolérées et réduisent nettement le risque cardiovasculaire. Signalez toute douleur musculaire à votre médecin."}]', ARRAY['Cholestérol élevé','Dyslipidémie','Hypercholestérolémie']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج ارتفاع الكوليسترول', 'يعتمد علاج ارتفاع الكوليسترول على تغذية متوازنة ونشاط بدني والإقلاع عن التدخين؛ وتُضاف أدوية (خاصة الستاتينات) حسب الخطر القلبي الوعائي الإجمالي. الهدف تقليل خطر الاحتشاء والسكتة بخفض الكوليسترول الضار (LDL).', 'تغذية متوازنة قليلة الدهون المشبعة
نشاط بدني منتظم والإقلاع عن التدخين
ستاتينات وأدوية أخرى حسب الخطر القلبي
ضبط العوامل الأخرى (الضغط، السكري، الوزن)', NULL, NULL, NULL, 'استشر لتقييم خطرك القلبي الوعائي وتكييف العلاج، أو عند آلام عضلية تحت الستاتين.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7b6000beghlxkpibwb3', 'Traitement de l''hypertension artérielle', 'traitement-hypertension-arterielle', 'medicamenteux', 'Le traitement de l''hypertension repose sur des mesures d''hygiène de vie (réduction du sel, activité physique, perte de poids) et, souvent, des médicaments antihypertenseurs. L''objectif est de ramener la tension à des valeurs cibles pour réduire le risque d''accident cardiovasculaire.', 'Réduction de la consommation de sel et alimentation équilibrée
Activité physique régulière et perte de poids si nécessaire
Médicaments antihypertenseurs (diurétiques, IEC, sartans, inhibiteurs calciques)
Arrêt du tabac et limitation de l''alcool', 'L''hypertension est une maladie chronique. Le traitement est généralement poursuivi au long cours, avec un suivi régulier de la tension et une adaptation des doses.', 'Fatigue, vertiges ou toux selon la classe de médicament
Gonflement des chevilles avec certains inhibiteurs calciques
Troubles urinaires ou ioniques avec les diurétiques', 'Tension très élevée avec maux de tête violents, troubles de la vue ou douleur thoracique
Essoufflement soudain ou malaise
Paralysie ou trouble de la parole (urgence AVC)', 'Consultez si votre tension reste élevée malgré le traitement, en cas d''effets indésirables gênants, ou immédiatement devant tout signe d''alerte.', '[{"q":"Le traitement de l''hypertension est-il à vie ?","a":"Le plus souvent oui, car l''hypertension est chronique. Certains patients réduisent leurs médicaments grâce à une hygiène de vie stricte, sous contrôle médical."},{"q":"Peut-on arrêter le traitement quand la tension est normale ?","a":"Non, sans avis médical : la tension normale est souvent le résultat du traitement. L''arrêter la ferait remonter."}]', ARRAY['HTA','Tension artérielle élevée']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج ارتفاع ضغط الدم', 'يعتمد علاج ارتفاع الضغط على تدابير نمط الحياة (تقليل الملح، النشاط البدني، إنقاص الوزن) وغالباً أدوية خافضة للضغط. الهدف إعادة الضغط إلى القيم المستهدفة لتقليل خطر الحوادث القلبية الوعائية.', 'تقليل استهلاك الملح وتغذية متوازنة
نشاط بدني منتظم وإنقاص الوزن عند الحاجة
أدوية خافضة للضغط
الإقلاع عن التدخين والحد من الكحول', NULL, NULL, NULL, 'استشر إذا بقي الضغط مرتفعاً رغم العلاج، أو عند آثار جانبية مزعجة، أو فوراً عند أي علامة إنذار.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7ci000geghl8ej1ydym', 'Traitement de l''hypothyroïdie', 'traitement-hypothyroidie', 'medicamenteux', 'L''hypothyroïdie se traite par un apport d''hormone thyroïdienne de synthèse (lévothyroxine), pris chaque matin à jeun. La dose est ajustée grâce au dosage sanguin de la TSH jusqu''à normalisation. Le traitement est le plus souvent poursuivi à vie.', 'Lévothyroxine : hormone thyroïdienne de substitution, prise quotidienne
Adaptation de la dose selon le taux de TSH
Surveillance biologique régulière', 'L''hypothyroïdie est le plus souvent définitive : le traitement est poursuivi à vie, avec un contrôle de la TSH quelques semaines après chaque changement de dose puis une à deux fois par an.', 'Signes de surdosage (palpitations, nervosité, insomnie) si la dose est trop élevée
Signes de sous-dosage (fatigue, frilosité) si la dose est insuffisante', 'Fatigue extrême, prise de poids et ralentissement importants
Palpitations ou tremblements marqués sous traitement', 'Consultez pour ajuster la dose en cas de symptômes de sur- ou sous-dosage, ou lors des contrôles de TSH recommandés.', '[{"q":"Pourquoi prendre la lévothyroxine à jeun ?","a":"Pour une absorption optimale, elle se prend le matin à jeun, environ 30 minutes avant le petit-déjeuner et à distance de certains médicaments (fer, calcium)."},{"q":"Le traitement est-il à vie ?","a":"Le plus souvent oui, car la glande thyroïde ne récupère généralement pas. La dose peut toutefois être ajustée dans le temps."}]', ARRAY['Thyroïde qui fonctionne au ralenti']::text[], (SELECT id FROM specialties WHERE slug='endocrinologie-et-maladies-metaboliques'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج قصور الغدة الدرقية', 'يُعالَج قصور الغدة الدرقية بتعويض هرمون درقي اصطناعي (الليفوثيروكسين) يؤخذ كل صباح على الريق. تُضبط الجرعة عبر قياس TSH في الدم حتى العودة للطبيعي. غالباً ما يستمر العلاج مدى الحياة.', 'الليفوثيروكسين: هرمون درقي بديل يؤخذ يومياً
ضبط الجرعة حسب مستوى TSH
مراقبة بيولوجية منتظمة', NULL, NULL, NULL, 'استشر لضبط الجرعة عند أعراض الزيادة أو النقص، أو عند مراقبة TSH الموصى بها.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i930001kshlvzpmxb98', 'Traitement de l''insomnie', 'traitement-insomnie', 'hygiene-de-vie', 'Le traitement de l''insomnie repose d''abord sur l''hygiène du sommeil et les thérapies comportementales (TCC de l''insomnie), très efficaces. Les somnifères ne sont utilisés qu''en dernier recours, sur une courte durée. Traiter une cause sous-jacente (stress, douleur, apnées) est essentiel.', 'Hygiène du sommeil : horaires réguliers, chambre sombre et calme, écrans limités le soir
Thérapie cognitivo-comportementale de l''insomnie (TCC-I)
Traitement d''une cause (stress, douleur, apnées du sommeil)
Somnifères en dernier recours et sur courte durée', 'Les mesures comportementales s''installent sur plusieurs semaines et donnent des résultats durables. Les somnifères, quand ils sont utilisés, le sont ponctuellement pour éviter l''accoutumance.', 'Somnolence diurne, chutes et dépendance avec les somnifères
Effet « rebond » possible à l''arrêt d''un somnifère pris trop longtemps', 'Somnolence dangereuse (au volant, au travail)
Ronflements avec pauses respiratoires (apnées du sommeil)
Insomnie associée à une tristesse profonde', 'Consultez si l''insomnie dure plusieurs semaines, retentit sur la journée, ou s''accompagne de ronflements avec pauses respiratoires.', '[{"q":"Les somnifères sont-ils une bonne solution ?","a":"Seulement en dépannage et sur une courte durée : ils exposent à l''accoutumance. Les thérapies comportementales sont le traitement de référence de l''insomnie chronique."},{"q":"Qu''est-ce que la TCC de l''insomnie ?","a":"Une thérapie brève qui agit sur les habitudes et les pensées liées au sommeil ; elle est très efficace et durable, sans médicament."}]', ARRAY['Troubles du sommeil','Difficultés d''endormissement']::text[], (SELECT id FROM specialties WHERE slug='psychiatrie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الأرق', 'يعتمد علاج الأرق أولاً على نظافة النوم والعلاجات السلوكية (العلاج المعرفي السلوكي للأرق)، وهي فعّالة جداً. لا تُستعمل المنوّمات إلا كملاذ أخير ولمدة قصيرة. معالجة سبب كامن (توتر، ألم، انقطاع نفس) أساسية.', 'نظافة النوم: مواعيد منتظمة، غرفة مظلمة وهادئة، تقليل الشاشات مساءً
العلاج المعرفي السلوكي للأرق
معالجة سبب (توتر، ألم، انقطاع النفس النومي)
منوّمات كملاذ أخير ولمدة قصيرة', NULL, NULL, NULL, 'استشر إذا استمر الأرق أسابيع أو أثّر على نهارك أو صاحبه شخير مع توقف التنفس.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i9o0004kshl8iwhm0zc', 'Traitement de l''ostéoporose', 'traitement-osteoporose', 'medicamenteux', 'Le traitement de l''ostéoporose associe un apport suffisant en calcium et vitamine D, une activité physique, la prévention des chutes et, selon le risque de fracture, des médicaments qui renforcent l''os (bisphosphonates notamment). L''objectif est d''éviter les fractures.', 'Apports en calcium et vitamine D adaptés
Activité physique et exercices d''équilibre
Prévention des chutes à domicile
Médicaments renforçant l''os (bisphosphonates, etc.) selon le risque', 'Le traitement médicamenteux se poursuit plusieurs années, avec réévaluation régulière. Les mesures de prévention (nutrition, activité, chutes) sont maintenues durablement.', 'Troubles digestifs avec les bisphosphonates oraux (respecter les consignes de prise)
Rares effets nécessitant un suivi', 'Fracture survenue sans choc important (poignet, hanche, vertèbre)
Perte de taille ou dos qui se voûte
Douleur dorsale brutale', 'Consultez après une fracture sans traumatisme important, ou pour évaluer votre risque après la ménopause ou sous corticoïdes prolongés.', '[{"q":"Le calcium suffit-il à traiter l''ostéoporose ?","a":"Le calcium et la vitamine D sont nécessaires mais souvent insuffisants seuls : un médicament renforçant l''os est ajouté selon le risque de fracture."},{"q":"L''ostéoporose est-elle douloureuse ?","a":"Pas en elle-même : elle est silencieuse jusqu''à la fracture. C''est pourquoi le dépistage et la prévention sont essentiels."}]', ARRAY['Fragilité osseuse','Déminéralisation osseuse']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج هشاشة العظام', 'يجمع علاج هشاشة العظام بين كمية كافية من الكالسيوم وفيتامين د، والنشاط البدني، والوقاية من السقوط، وحسب خطر الكسر أدوية تقوّي العظم (خاصة البيسفوسفونات). الهدف تجنّب الكسور.', 'كمية مناسبة من الكالسيوم وفيتامين د
نشاط بدني وتمارين توازن
الوقاية من السقوط في المنزل
أدوية تقوّي العظم حسب الخطر', NULL, NULL, NULL, 'استشر بعد كسر دون صدمة قوية، أو لتقييم خطرك بعد سن اليأس أو تحت الكورتيزون المطوّل.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iay000ckshl4cm108jo', 'Traitement de l''otite', 'traitement-otite', 'medicamenteux', 'Le traitement de l''otite dépend de son type : l''otite moyenne aiguë se soulage par des antalgiques, les antibiotiques étant réservés à certains cas (jeune enfant, symptômes marqués). L''otite externe se traite par des gouttes locales. Une otite qui traîne ou récidive nécessite un avis ORL.', 'Antalgiques et antipyrétiques pour la douleur et la fièvre
Antibiotiques dans certains cas d''otite moyenne (selon l''âge et la sévérité)
Gouttes auriculaires pour l''otite externe
Avis ORL en cas de récidives ou d''otite persistante', 'La douleur d''une otite s''améliore en quelques jours. Les otites à répétition, surtout chez l''enfant, justifient un bilan ORL.', 'Effets digestifs des antibiotiques quand ils sont prescrits', 'Douleur intense avec fièvre élevée
Écoulement de l''oreille, gonflement ou rougeur derrière l''oreille
Baisse d''audition persistante ou vertiges', 'Consultez en cas de douleur intense, de fièvre élevée, d''écoulement de l''oreille, ou chez le jeune enfant, et si les symptômes persistent.', '[{"q":"L''otite nécessite-t-elle des antibiotiques ?","a":"Pas toujours : chez le grand enfant et l''adulte, un traitement de la douleur suffit souvent. Les antibiotiques sont réservés à certains cas."},{"q":"Peut-on mettre des gouttes dans l''oreille ?","a":"Seulement sur avis médical : les gouttes conviennent à l''otite externe, mais pas en cas de tympan perforé sans indication précise."}]', ARRAY['Otite moyenne','Infection de l''oreille']::text[], (SELECT id FROM specialties WHERE slug='oto-rhino-laryngologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب الأذن', 'يعتمد علاج التهاب الأذن على نوعه: التهاب الأذن الوسطى الحاد يُخفَّف بالمسكّنات، وتُخصَّص المضادات الحيوية لبعض الحالات (الطفل الصغير، أعراض شديدة). يُعالَج التهاب الأذن الخارجية بقطرات موضعية. يتطلّب الالتهاب المستمر أو المتكرر رأي أخصائي.', 'مسكّنات وخافضات حرارة للألم والحمى
مضادات حيوية في بعض حالات الأذن الوسطى (حسب السن والشدة)
قطرات للأذن في التهاب الأذن الخارجية
رأي أخصائي عند التكرار أو الاستمرار', NULL, NULL, NULL, 'استشر عند ألم شديد أو حمى عالية أو إفراز من الأذن، أو عند الطفل الصغير، وإذا استمرت الأعراض.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iag0008kshll4aoyw0m', 'Traitement de l''ulcère gastroduodénal', 'traitement-ulcere-gastrique', 'medicamenteux', 'Le traitement de l''ulcère associe des médicaments qui réduisent l''acidité (inhibiteurs de la pompe à protons) et, en cas d''infection à Helicobacter pylori, des antibiotiques pour l''éradiquer. Il faut aussi éviter le tabac et les anti-inflammatoires. La guérison est la règle avec un traitement bien suivi.', 'Inhibiteurs de la pompe à protons (réduction de l''acidité)
Éradication d''Helicobacter pylori par antibiotiques si présent
Arrêt du tabac et des anti-inflammatoires
Contrôle endoscopique dans certains cas', 'Le traitement dure quelques semaines. L''éradication d''Helicobacter pylori se fait sur une cure définie, souvent avec un contrôle de son efficacité.', 'Troubles digestifs possibles sous antibiotiques
Interactions et effets d''un usage prolongé des IPP à discuter', 'Vomissements de sang ou selles noires
Douleur abdominale brutale et intense
Amaigrissement ou difficulté à avaler', 'Consultez en cas de douleurs de l''estomac persistantes, et en urgence devant un vomissement de sang, des selles noires ou une douleur brutale.', '[{"q":"L''ulcère est-il dû au stress ?","a":"Le stress peut aggraver les symptômes, mais les causes principales sont l''infection à Helicobacter pylori et les anti-inflammatoires."},{"q":"L''ulcère guérit-il ?","a":"Oui, avec un traitement bien suivi (réduction de l''acidité et, si besoin, éradication de la bactérie), la guérison est la règle."}]', ARRAY['Ulcère de l''estomac','Ulcère duodénal']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج قرحة المعدة والاثني عشر', 'يجمع علاج القرحة بين أدوية تقلّل الحموضة (مثبطات مضخة البروتون)، وعند وجود جرثومة المعدة مضادات حيوية للقضاء عليها. يجب أيضاً تجنّب التدخين ومضادات الالتهاب. الشفاء هو القاعدة مع علاج جيد.', 'مثبطات مضخة البروتون (تقليل الحموضة)
القضاء على جرثومة المعدة بالمضادات الحيوية عند وجودها
الإقلاع عن التدخين ومضادات الالتهاب
تنظير للمراقبة في بعض الحالات', NULL, NULL, NULL, 'استشر عند آلام معدية مستمرة، وطارئاً عند تقيؤ دم أو براز أسود أو ألم مفاجئ.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ib3000dkshlas6zg6p6', 'Traitement de la bronchite', 'traitement-bronchite', 'medicamenteux', 'La bronchite aiguë est le plus souvent virale et guérit seule en une à trois semaines : repos, hydratation et antalgiques suffisent. Les antibiotiques sont inutiles dans la forme virale. La toux peut persister quelques semaines. Un avis médical est nécessaire en cas de gêne respiratoire ou de fièvre prolongée.', 'Repos, hydratation et antalgiques/antipyrétiques
Arrêt du tabac et éviction des irritants
Pas d''antibiotiques dans la bronchite virale
Avis médical si gêne respiratoire ou terrain fragile', 'La bronchite aiguë guérit en une à trois semaines. La toux résiduelle peut durer plusieurs semaines sans gravité.', 'Effets des antibiotiques s''ils sont prescrits à tort (à éviter)', 'Essoufflement, respiration sifflante ou douleur thoracique
Fièvre élevée persistante au-delà de quelques jours
Crachats sanglants ou état général altéré', 'Consultez en cas de gêne respiratoire, de fièvre prolongée, de crachats sanglants, ou si vous êtes fragile (asthme, BPCO, personne âgée).', '[{"q":"Faut-il des antibiotiques pour une bronchite ?","a":"Non dans la forme aiguë virale, la plus fréquente : ils sont inutiles. Ils ne se justifient que sur avis médical dans certaines situations."},{"q":"Pourquoi la toux dure-t-elle si longtemps ?","a":"Après une bronchite, les bronches restent irritées : une toux sèche peut persister plusieurs semaines sans gravité."}]', ARRAY['Bronchite aiguë','Inflammation des bronches']::text[], (SELECT id FROM specialties WHERE slug='pneumo-phtisiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب القصبات', 'التهاب القصبات الحاد غالباً فيروسي ويُشفى وحده في أسبوع إلى ثلاثة: راحة وترطيب ومسكّنات تكفي. المضادات الحيوية غير مفيدة في الشكل الفيروسي. قد يستمرّ السعال أسابيع. يلزم رأي طبي عند ضيق التنفس أو حمى مطوّلة.', 'راحة وترطيب ومسكّنات/خافضات حرارة
الإقلاع عن التدخين وتجنّب المهيّجات
لا مضادات حيوية في الالتهاب الفيروسي
رأي طبي عند ضيق التنفس أو هشاشة الحالة', NULL, NULL, NULL, 'استشر عند ضيق التنفس أو حمى مطوّلة أو بلغم دموي، أو إذا كنت هشّاً (ربو، انسداد رئوي، مسنّ).', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ibi000gkshl6c7keep8', 'Traitement de la conjonctivite', 'traitement-conjonctivite', 'medicamenteux', 'Le traitement de la conjonctivite dépend de sa cause : lavages au sérum physiologique et hygiène pour la forme virale, antihistaminiques pour la forme allergique, collyre antibiotique seulement si origine bactérienne. La plupart des conjonctivites guérissent en quelques jours. L''hygiène des mains limite la contagion.', 'Lavages oculaires au sérum physiologique et hygiène des mains
Antihistaminiques (collyre) pour la conjonctivite allergique
Collyre antibiotique uniquement si origine bactérienne
Éviter le port de lentilles pendant l''épisode', 'Une conjonctivite virale ou bactérienne guérit généralement en quelques jours à une semaine. La forme allergique dure tant que dure l''exposition à l''allergène.', 'Picotements passagers avec certains collyres', 'Baisse de la vision, douleur oculaire intense
Sensibilité marquée à la lumière
Œil rouge chez un porteur de lentilles (à traiter en urgence)', 'Consultez en cas de baisse de vision, de douleur intense, de forte sensibilité à la lumière, ou d''œil rouge chez un porteur de lentilles.', '[{"q":"La conjonctivite est-elle contagieuse ?","a":"Les formes virales et bactériennes le sont. Se laver les mains, ne pas partager serviette ni maquillage limite la transmission."},{"q":"Faut-il toujours un collyre antibiotique ?","a":"Non : il n''est utile que pour les conjonctivites bactériennes. Les formes virales et allergiques relèvent d''autres soins."}]', ARRAY['Œil rouge','Inflammation de la conjonctive']::text[], (SELECT id FROM specialties WHERE slug='ophtalmologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب الملتحمة', 'يعتمد علاج التهاب الملتحمة على سببه: غسل بالمصل الفيزيولوجي والنظافة للشكل الفيروسي، مضادات الهيستامين للشكل التحسسي، وقطرة مضاد حيوي فقط عند سبب جرثومي. تُشفى معظم الحالات في أيام. نظافة اليدين تحدّ من العدوى.', 'غسل العين بالمصل الفيزيولوجي ونظافة اليدين
مضادات الهيستامين (قطرة) للشكل التحسسي
قطرة مضاد حيوي فقط عند سبب جرثومي
تجنّب العدسات اللاصقة أثناء النوبة', NULL, NULL, NULL, 'استشر عند تراجع الرؤية أو ألم شديد أو حساسية قوية للضوء، أو احمرار العين عند مستعمل العدسات.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iab0007kshlruj2eto1', 'Traitement de la constipation', 'traitement-constipation', 'hygiene-de-vie', 'Le traitement de la constipation repose d''abord sur les mesures d''hygiène de vie : fibres, hydratation suffisante et activité physique. Les laxatifs doux (à base de fibres ou osmotiques) sont utilisés si besoin. Il faut rechercher et traiter une cause en cas de constipation récente ou persistante.', 'Alimentation riche en fibres (fruits, légumes, céréales complètes)
Hydratation suffisante et activité physique régulière
Aller à la selle sans se retenir, à heure régulière
Laxatifs doux (fibres, osmotiques) si nécessaire', 'Les mesures d''hygiène de vie sont durables. Les laxatifs s''utilisent ponctuellement ; une constipation chronique nécessite un avis médical.', 'Ballonnements avec les fibres au début (augmentation progressive)
Dépendance possible aux laxatifs stimulants (à éviter au long cours)', 'Constipation récente et inhabituelle après 50 ans
Sang dans les selles ou amaigrissement
Douleurs abdominales importantes ou arrêt des gaz', 'Consultez en cas de constipation récente et persistante, de sang dans les selles, d''amaigrissement ou de douleurs importantes.', '[{"q":"Les laxatifs sont-ils dangereux ?","a":"Les laxatifs doux sont sûrs ponctuellement. Les laxatifs stimulants ne doivent pas être utilisés au long cours sans avis médical."},{"q":"Combien boire d''eau ?","a":"Une hydratation suffisante (souvent autour de 1,5 L/jour, adaptée à chacun) aide, associée aux fibres et à l''activité physique."}]', ARRAY['Transit ralenti']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الإمساك', 'يعتمد علاج الإمساك أولاً على تدابير نمط الحياة: الألياف والترطيب الكافي والنشاط البدني. تُستعمل الملينات اللطيفة عند الحاجة. يجب البحث عن سبب ومعالجته عند إمساك حديث أو مستمر.', 'تغذية غنية بالألياف (فواكه، خضر، حبوب كاملة)
ترطيب كافٍ ونشاط بدني منتظم
عدم كبت الرغبة في التبرّز
ملينات لطيفة عند الحاجة', NULL, NULL, NULL, 'استشر عند إمساك حديث ومستمر أو دم في البراز أو فقدان وزن أو آلام مهمة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ibo000hkshlgujyhqky', 'Traitement de la cystite (infection urinaire)', 'traitement-cystite', 'medicamenteux', 'La cystite se traite par un antibiotique adapté, souvent sur une courte durée, avec une bonne hydratation. Chez la femme sans facteur de risque, la guérison est rapide. Il faut consulter en cas de fièvre, de douleurs lombaires, chez l''homme, la femme enceinte ou l''enfant.', 'Antibiotique adapté (souvent cure courte) sur avis médical
Hydratation abondante
Mesures d''hygiène et mictions régulières
Examen des urines (ECBU) selon les cas', 'Une cystite simple guérit en quelques jours avec l''antibiotique adapté. Les cystites récidivantes justifient un bilan.', 'Effets digestifs possibles des antibiotiques', 'Fièvre, frissons ou douleurs dans le bas du dos (atteinte du rein)
Sang dans les urines
Infection urinaire chez l''homme, la femme enceinte ou l''enfant', 'Consultez en cas de fièvre, de douleurs lombaires, de sang dans les urines, ou si vous êtes un homme, une femme enceinte ou un enfant.', '[{"q":"Peut-on soigner une cystite sans antibiotique ?","a":"Une cystite simple nécessite le plus souvent un antibiotique adapté. L''hydratation aide mais ne remplace pas le traitement en cas d''infection avérée."},{"q":"Quand la cystite devient-elle grave ?","a":"En cas de fièvre, de frissons ou de douleurs lombaires : l''infection peut atteindre le rein (pyélonéphrite) et nécessite une consultation rapide."}]', ARRAY['Infection urinaire','Cystite aiguë']::text[], (SELECT id FROM specialties WHERE slug='medecine-generale'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب المثانة (العدوى البولية)', 'يُعالَج التهاب المثانة بمضاد حيوي مناسب، غالباً لمدة قصيرة، مع ترطيب جيد. عند المرأة دون عوامل خطر يكون الشفاء سريعاً. يجب الاستشارة عند الحمى أو ألم أسفل الظهر، أو عند الرجل والحامل والطفل.', 'مضاد حيوي مناسب (غالباً مدة قصيرة) بإشراف طبي
ترطيب وفير
تدابير نظافة وتبوّل منتظم
تحليل بول حسب الحالة', NULL, NULL, NULL, 'استشر عند الحمى أو ألم أسفل الظهر أو دم في البول، أو إذا كنت رجلاً أو حاملاً أو طفلاً.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7cw000ieghl2k3gffq4', 'Traitement de la dépression', 'traitement-depression', 'medicamenteux', 'Le traitement de la dépression associe une psychothérapie et, selon la sévérité, des médicaments antidépresseurs. Le soutien de l''entourage et une bonne hygiène de vie sont importants. La prise en charge est adaptée à chaque personne et nécessite un suivi régulier.', 'Psychothérapie (thérapies cognitivo-comportementales notamment)
Antidépresseurs selon la sévérité et la durée des symptômes
Soutien de l''entourage et hygiène de vie (sommeil, activité physique)
Suivi régulier pour évaluer l''efficacité et la tolérance', 'Le traitement antidépresseur, quand il est prescrit, met plusieurs semaines à agir pleinement et se poursuit généralement plusieurs mois après l''amélioration pour éviter les rechutes.', 'Effets transitoires en début de traitement (troubles digestifs, sommeil)
Ne jamais arrêter brutalement un antidépresseur sans avis médical', 'Idées noires ou pensées suicidaires
Incapacité à assurer les gestes du quotidien
Aggravation rapide de l''humeur', 'Consultez sans attendre en cas de tristesse persistante retentissant sur la vie quotidienne, et en urgence en présence d''idées suicidaires.', '[{"q":"Les antidépresseurs rendent-ils dépendant ?","a":"Non, ils ne créent pas de dépendance. Ils ne doivent toutefois pas être arrêtés brutalement, mais diminués progressivement sous contrôle médical."},{"q":"La psychothérapie suffit-elle ?","a":"Pour les formes légères à modérées, la psychothérapie peut suffire. Les formes plus sévères associent souvent psychothérapie et médicaments."}]', ARRAY['Dépression','Épisode dépressif']::text[], (SELECT id FROM specialties WHERE slug='psychiatrie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الاكتئاب', 'يجمع علاج الاكتئاب بين العلاج النفسي، وحسب الشدة، أدوية مضادة للاكتئاب. دعم المحيط ونمط حياة سليم مهمان. تُكيَّف الرعاية مع كل شخص وتتطلب متابعة منتظمة.', 'العلاج النفسي (خاصة العلاج المعرفي السلوكي)
مضادات الاكتئاب حسب الشدة ومدة الأعراض
دعم المحيط ونمط حياة سليم
متابعة منتظمة لتقييم الفعالية والتحمّل', NULL, NULL, NULL, 'استشر دون تأخير عند حزن مستمر يؤثر على الحياة اليومية، وطارئاً عند وجود أفكار انتحارية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ia50006kshlwtpjm9q6', 'Traitement de la goutte', 'traitement-goutte', 'medicamenteux', 'Le traitement de la goutte comprend la prise en charge de la crise (anti-inflammatoires, colchicine) et, en cas de crises répétées, un traitement de fond qui abaisse l''acide urique. Des mesures alimentaires (limiter alcool, sodas sucrés, excès de viande) complètent le traitement.', 'Traitement de la crise : anti-inflammatoires ou colchicine, tôt
Traitement de fond hypo-uricémiant si crises répétées
Mesures alimentaires : limiter alcool, sodas sucrés, abats et excès de viande
Bonne hydratation', 'La crise se calme en quelques jours. Le traitement de fond, quand il est indiqué, se prend au long cours pour normaliser durablement l''acide urique.', 'Troubles digestifs avec la colchicine (respecter la dose)
Possible crise au démarrage du traitement de fond (encadrée par le médecin)', 'Articulation brutalement rouge, chaude et très douloureuse
Fièvre associée (écarter une infection articulaire)
Crises de plus en plus fréquentes', 'Consultez en cas de crises répétées ou d''articulation très inflammatoire, pour discuter d''un traitement de fond et écarter une infection.', '[{"q":"L''alimentation suffit-elle à traiter la goutte ?","a":"Elle aide mais ne suffit souvent pas en cas de crises répétées : un traitement abaissant l''acide urique est alors nécessaire."},{"q":"Que faire pendant une crise ?","a":"Prendre le traitement de crise le plus tôt possible, reposer et surélever l''articulation, bien s''hydrater, et consulter si besoin."}]', ARRAY['Crise de goutte','Hyperuricémie']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج داء النقرس', 'يشمل علاج النقرس معالجة النوبة (مضادات التهاب، الكولشيسين)، وعند تكرار النوبات علاجاً أساسياً يخفض حمض البول. تكمّله تدابير غذائية (الحد من الكحول والمشروبات السكرية والإفراط في اللحوم).', 'علاج النوبة: مضادات التهاب أو الكولشيسين مبكراً
علاج أساسي خافض لحمض البول عند تكرار النوبات
تدابير غذائية: الحد من الكحول والمشروبات السكرية واللحوم
ترطيب جيد', NULL, NULL, NULL, 'استشر عند تكرار النوبات أو مفصل شديد الالتهاب، لمناقشة علاج أساسي واستبعاد عدوى.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i9u0005kshl27m2q8e9', 'Traitement de la lombalgie (mal de dos)', 'traitement-lombalgie', 'fonctionnel', 'Le traitement de la lombalgie repose surtout sur le maintien de l''activité, des antalgiques simples si besoin et des exercices de renforcement. Le repos prolongé est déconseillé. La plupart des lombalgies aiguës guérissent en quelques semaines ; la kinésithérapie aide en cas de douleurs persistantes.', 'Maintien d''une activité physique (éviter l''alitement)
Antalgiques simples lors des douleurs
Exercices de renforcement et kinésithérapie
Correction des postures et de l''ergonomie', 'Une lombalgie aiguë guérit généralement en quelques semaines. Au-delà de trois mois (lombalgie chronique), la prise en charge repose sur l''activité et la rééducation.', 'Troubles digestifs avec les anti-inflammatoires (usage limité)', 'Douleur descendant dans la jambe avec faiblesse ou perte de sensibilité
Troubles pour uriner ou aller à la selle
Fièvre, amaigrissement ou douleur nocturne intense', 'Consultez si la douleur persiste au-delà de quelques semaines, s''aggrave, ou s''accompagne d''un signe d''alerte neurologique.', '[{"q":"Faut-il rester couché quand on a mal au dos ?","a":"Non. Le maintien d''une activité adaptée accélère la guérison ; le repos prolongé au lit aggrave et prolonge la lombalgie."},{"q":"Quand s''inquiéter d''un mal de dos ?","a":"En cas de douleur descendant dans la jambe avec faiblesse, de troubles urinaires, de fièvre ou d''amaigrissement : consultez rapidement."}]', ARRAY['Mal de dos','Lumbago','Douleur lombaire']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج ألم أسفل الظهر', 'يعتمد علاج ألم أسفل الظهر أساساً على الحفاظ على النشاط، ومسكّنات بسيطة عند الحاجة، وتمارين تقوية. الراحة المطوّلة غير مستحسنة. تُشفى معظم الآلام الحادة في أسابيع؛ ويساعد العلاج الطبيعي عند استمرارها.', 'الحفاظ على النشاط البدني (تجنّب ملازمة الفراش)
مسكّنات بسيطة أثناء الألم
تمارين تقوية وعلاج طبيعي
تصحيح الوضعيات', NULL, NULL, NULL, 'استشر إذا استمر الألم أكثر من بضعة أسابيع أو ازداد أو صاحبته علامة إنذار عصبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7by000eeghlnk6slb7i', 'Traitement de la migraine', 'traitement-migraine', 'medicamenteux', 'Le traitement de la migraine comprend un traitement de crise (antalgiques ou triptans pris dès le début de la douleur) et, si les crises sont fréquentes, un traitement de fond pour les réduire. Identifier et éviter les facteurs déclenchants est complémentaire.', 'Traitement de crise : antalgiques simples ou triptans, pris tôt
Traitement de fond si crises fréquentes (plusieurs par mois)
Identification et éviction des facteurs déclenchants (stress, sommeil, alimentation)
Tenue d''un agenda des crises', 'La migraine est chronique et évolue par crises. Le traitement de crise est ponctuel ; le traitement de fond, quand il est indiqué, se prend plusieurs mois puis est réévalué.', 'Risque de céphalées par abus d''antalgiques en cas de prise trop fréquente
Effets propres aux triptans (sensation d''oppression, fourmillements)', 'Mal de tête brutal et inhabituel, « en coup de tonnerre »
Céphalée avec fièvre, raideur de nuque, trouble de la vue ou de la parole
Migraine qui change de caractère ou s''aggrave', 'Consultez si les crises sont fréquentes, invalidantes ou résistantes, et consultez en urgence devant tout signe d''alerte neurologique.', '[{"q":"Quand prendre le traitement de crise ?","a":"Le plus tôt possible dès le début de la douleur : les triptans et antalgiques sont d''autant plus efficaces qu''ils sont pris rapidement."},{"q":"Prendre des antalgiques trop souvent est-il risqué ?","a":"Oui. Un usage trop fréquent peut entretenir des céphalées « par abus médicamenteux ». Au-delà de quelques crises par mois, parlez d''un traitement de fond à votre médecin."}]', ARRAY['Céphalée migraineuse']::text[], (SELECT id FROM specialties WHERE slug='neurologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الشقيقة', 'يشمل علاج الشقيقة علاج النوبة (مسكّنات أو تريبتانات تؤخذ فور بدء الألم)، وإذا كانت النوبات متكررة علاجاً أساسياً لتقليلها. تحديد العوامل المحفزة وتجنّبها مكمّل.', 'علاج النوبة: مسكّنات بسيطة أو تريبتانات، تؤخذ مبكراً
علاج أساسي عند تكرر النوبات
تحديد وتجنّب العوامل المحفزة
تدوين مذكرة للنوبات', NULL, NULL, NULL, 'استشر إذا كانت النوبات متكررة أو مُعيقة أو مقاومة، واستشر طارئاً عند أي علامة إنذار عصبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1i9e0003kshlek2b0ye2', 'Traitement de la polyarthrite rhumatoïde', 'traitement-polyarthrite-rhumatoide', 'medicamenteux', 'La polyarthrite rhumatoïde se traite par des médicaments de fond (dont le méthotrexate) qui freinent l''inflammation et protègent les articulations, complétés par des anti-inflammatoires lors des poussées. Un traitement précoce et un suivi rapproché limitent les déformations. Les biothérapies existent pour les formes résistantes.', 'Traitements de fond (méthotrexate en première intention)
Anti-inflammatoires et corticoïdes lors des poussées
Biothérapies pour les formes résistantes
Kinésithérapie et éducation thérapeutique', 'Maladie chronique auto-immune : le traitement de fond est au long cours, avec une surveillance biologique régulière et des ajustements selon l''activité de la maladie.', 'Surveillance sanguine nécessaire sous méthotrexate
Risque infectieux accru sous biothérapies', 'Articulations très gonflées, chaudes et raides le matin de façon prolongée
Fièvre ou infection sous traitement immunosuppresseur
Aggravation rapide malgré le traitement', 'Consultez rapidement un rhumatologue en cas de douleurs articulaires inflammatoires persistantes : un traitement précoce protège les articulations.', '[{"q":"La polyarthrite rhumatoïde se guérit-elle ?","a":"Elle ne se guérit pas mais se contrôle très bien aujourd''hui. Un traitement précoce permet souvent une rémission et évite les déformations."},{"q":"Le méthotrexate est-il dangereux ?","a":"Utilisé aux doses de la polyarthrite et sous surveillance sanguine régulière, il est efficace et bien encadré."}]', ARRAY['PR','Arthrite rhumatoïde']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب المفاصل الروماتويدي', 'يُعالَج التهاب المفاصل الروماتويدي بأدوية أساسية (منها الميثوتريكسات) تكبح الالتهاب وتحمي المفاصل، مع مضادات التهاب أثناء النوبات. العلاج المبكر والمتابعة اللصيقة يحدّان من التشوهات. توجد علاجات بيولوجية للأشكال المقاومة.', 'أدوية أساسية (الميثوتريكسات أولاً)
مضادات التهاب وكورتيكويدات أثناء النوبات
علاجات بيولوجية للأشكال المقاومة
علاج طبيعي وتثقيف علاجي', NULL, NULL, NULL, 'استشر طبيب الروماتيزم بسرعة عند آلام مفصلية التهابية مستمرة: العلاج المبكر يحمي المفاصل.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7cb000feghlc5csdmto', 'Traitement de la rhinite allergique', 'traitement-rhinite-allergique', 'medicamenteux', 'Le traitement de la rhinite allergique associe l''éviction de l''allergène quand c''est possible, des antihistaminiques et des corticoïdes en spray nasal pour calmer les symptômes. En cas d''allergie invalidante, une désensibilisation peut être proposée.', 'Éviction de l''allergène (pollens, acariens, poils d''animaux) quand c''est possible
Antihistaminiques oraux
Corticoïdes en spray nasal
Lavages de nez au sérum physiologique
Désensibilisation (immunothérapie allergénique) dans certains cas', 'La rhinite allergique est souvent saisonnière ou chronique. Le traitement se prend pendant les périodes d''exposition ; la désensibilisation, quand elle est indiquée, dure plusieurs années.', 'Somnolence avec certains antihistaminiques (privilégier ceux de nouvelle génération)
Irritation ou sécheresse nasale avec les sprays', 'Gêne respiratoire, sifflements ou essoufflement (possible asthme associé)
Symptômes persistants malgré le traitement bien conduit', 'Consultez un allergologue en cas de symptômes persistants, invalidants, ou associés à un asthme, pour un bilan et une éventuelle désensibilisation.', '[{"q":"La rhinite allergique peut-elle évoluer en asthme ?","a":"Une rhinite allergique mal contrôlée peut s''accompagner d''asthme. C''est pourquoi il est important de la traiter et de surveiller la respiration."},{"q":"La désensibilisation guérit-elle l''allergie ?","a":"Elle peut réduire durablement les symptômes en habituant progressivement l''organisme à l''allergène, mais elle demande plusieurs années et un suivi spécialisé."}]', ARRAY['Rhume des foins','Rhinite saisonnière']::text[], (SELECT id FROM specialties WHERE slug='allergologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب الأنف التحسسي', 'يجمع علاج التهاب الأنف التحسسي بين تجنّب المُحسِّس عند الإمكان، ومضادات الهيستامين، والكورتيكويدات برذاذ أنفي لتهدئة الأعراض. عند الحساسية المُعيقة قد يُقترح إزالة التحسس.', 'تجنّب المُحسِّس (اللقاح، عث الغبار، وبر الحيوانات) عند الإمكان
مضادات الهيستامين الفموية
كورتيكويدات برذاذ أنفي
غسل الأنف بالمصل الفيزيولوجي
إزالة التحسس في بعض الحالات', NULL, NULL, NULL, 'استشر طبيب حساسية عند أعراض مستمرة أو مُعيقة أو مصحوبة بربو، لإجراء تقييم وإزالة تحسس محتملة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iap000akshlv7h671ov', 'Traitement de la sinusite', 'traitement-sinusite', 'medicamenteux', 'La plupart des sinusites sont virales et guérissent seules : lavages de nez au sérum physiologique, antalgiques et parfois corticoïdes locaux suffisent. Les antibiotiques ne sont utiles que dans les sinusites bactériennes. Une sinusite qui traîne ou récidive nécessite un avis ORL.', 'Lavages de nez au sérum physiologique
Antalgiques et antipyrétiques
Corticoïdes locaux (spray nasal) si besoin
Antibiotiques uniquement en cas de sinusite bactérienne avérée', 'Une sinusite virale s''améliore en une dizaine de jours. Une sinusite bactérienne traitée par antibiotiques guérit en quelques jours ; les formes chroniques relèvent de l''ORL.', 'Sécheresse ou irritation nasale avec les sprays
Effets des antibiotiques quand ils sont réellement nécessaires', 'Fièvre élevée persistante, gonflement ou rougeur autour de l''œil
Maux de tête violents, troubles de la vue
Symptômes qui s''aggravent après une amélioration', 'Consultez si les symptômes durent plus de dix jours, s''aggravent, ou en urgence en cas de gonflement de l''œil ou de maux de tête violents.', '[{"q":"Faut-il des antibiotiques pour une sinusite ?","a":"Non dans la majorité des cas, car la plupart des sinusites sont virales. Les antibiotiques sont réservés aux sinusites bactériennes confirmées."},{"q":"Les lavages de nez sont-ils utiles ?","a":"Oui, ils dégagent les sinus et soulagent efficacement les symptômes, sans effet indésirable notable."}]', ARRAY['Rhinosinusite','Infection des sinus']::text[], (SELECT id FROM specialties WHERE slug='oto-rhino-laryngologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج التهاب الجيوب الأنفية', 'معظم التهابات الجيوب فيروسية وتُشفى وحدها: غسل الأنف بالمصل الفيزيولوجي ومسكّنات وأحياناً كورتيكويدات موضعية تكفي. لا تفيد المضادات الحيوية إلا في الالتهاب الجرثومي. يتطلّب التهاب مستمر أو متكرر رأي أخصائي أنف وأذن وحنجرة.', 'غسل الأنف بالمصل الفيزيولوجي
مسكّنات وخافضات حرارة
كورتيكويدات موضعية عند الحاجة
مضادات حيوية فقط في الالتهاب الجرثومي المؤكّد', NULL, NULL, NULL, 'استشر إذا استمرت الأعراض أكثر من عشرة أيام أو ازدادت، وطارئاً عند تورّم العين أو صداع شديد.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1iak0009kshlsv8ose4p', 'Traitement des hémorroïdes', 'traitement-hemorroides', 'medicamenteux', 'Le traitement des hémorroïdes commence par la régularisation du transit (fibres, hydratation) et des soins locaux (crèmes, veinotoniques) lors des crises. Les formes gênantes ou récidivantes relèvent de traitements instrumentaux ou chirurgicaux. La plupart des poussées se calment en quelques jours.', 'Régularisation du transit : fibres, hydratation, éviter la constipation
Soins locaux (crèmes, suppositoires) et veinotoniques lors des crises
Traitements instrumentaux (ligature) pour les formes récidivantes
Chirurgie dans les formes sévères', 'Une poussée hémorroïdaire se calme généralement en quelques jours avec les soins. Les mesures sur le transit sont maintenues pour éviter les récidives.', 'Irritation locale possible avec certaines crèmes
Suites simples après un geste instrumental', 'Saignement abondant ou persistant par l''anus
Douleur anale intense et brutale
Saignement chez une personne de plus de 50 ans (écarter une autre cause)', 'Consultez en cas de saignement persistant, de douleur intense, ou de tout saignement inhabituel après 50 ans pour écarter une autre cause.', '[{"q":"Les hémorroïdes sont-elles graves ?","a":"Le plus souvent bénignes, elles sont gênantes. Tout saignement doit toutefois être évalué, surtout après 50 ans, pour ne pas passer à côté d''une autre cause."},{"q":"Comment éviter les récidives ?","a":"En luttant contre la constipation : alimentation riche en fibres, bonne hydratation et transit régulier sans efforts de poussée."}]', ARRAY['Crise hémorroïdaire','Maladie hémorroïdaire']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج البواسير', 'يبدأ علاج البواسير بتنظيم التبرّز (ألياف، ترطيب) وعلاجات موضعية (كريمات، مقوّيات وريدية) أثناء النوبات. تُعالَج الأشكال المزعجة أو المتكررة بإجراءات أو جراحة. تهدأ معظم النوبات في أيام.', 'تنظيم التبرّز: ألياف، ترطيب، تجنّب الإمساك
علاجات موضعية ومقوّيات وريدية أثناء النوبات
إجراءات (ربط) للأشكال المتكررة
جراحة في الأشكال الشديدة', NULL, NULL, NULL, 'استشر عند نزيف مستمر أو ألم شديد أو أي نزيف غير معتاد بعد سن الخمسين لاستبعاد سبب آخر.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ibd000fkshl9ranw5fo', 'Traitement des mycoses cutanées', 'traitement-mycose-cutanee', 'medicamenteux', 'Le traitement des mycoses de la peau repose sur des antifongiques, le plus souvent en crème (parfois par voie orale pour les ongles ou les formes étendues). Garder la peau propre et sèche accélère la guérison et prévient les récidives. La plupart des mycoses cutanées guérissent bien.', 'Antifongiques locaux (crème, poudre) pour la peau
Antifongiques par voie orale pour les ongles ou formes étendues
Garder la peau propre et sèche, éviter la macération
Désinfecter chaussures et linge pour éviter les récidives', 'Une mycose de la peau guérit en une à quelques semaines de traitement bien suivi. Les mycoses des ongles demandent plusieurs mois.', 'Irritation locale possible avec les crèmes
Surveillance pour les antifongiques oraux prolongés', 'Lésion étendue, suintante ou surinfectée
Mycose résistante malgré un traitement bien conduit
Terrain fragilisé (diabète, immunodépression)', 'Consultez un dermatologue si la mycose s''étend, résiste au traitement, touche les ongles, ou en cas de diabète ou d''immunodépression.', '[{"q":"Les mycoses sont-elles contagieuses ?","a":"Certaines le sont (par contact direct, sols humides, linge partagé). Une bonne hygiène et le traitement limitent la transmission."},{"q":"Pourquoi ma mycose revient-elle ?","a":"Souvent à cause de l''humidité et de la macération. Garder la peau sèche, changer de chaussettes et désinfecter le linge aide à éviter les récidives."}]', ARRAY['Mycose de la peau','Dermatophytie','Candidose cutanée']::text[], (SELECT id FROM specialties WHERE slug='dermatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الفطريات الجلدية', 'يعتمد علاج فطريات الجلد على مضادات الفطريات، غالباً ككريم (وأحياناً فموياً للأظافر أو الأشكال الواسعة). الحفاظ على الجلد نظيفاً وجافاً يسرّع الشفاء ويمنع التكرار. تُشفى معظم الفطريات الجلدية جيداً.', 'مضادات فطريات موضعية للجلد
مضادات فطريات فموية للأظافر أو الأشكال الواسعة
إبقاء الجلد نظيفاً وجافاً وتجنّب الرطوبة
تعقيم الأحذية والملابس لتفادي التكرار', NULL, NULL, NULL, 'استشر طبيب أمراض جلدية إذا اتسعت الفطريات أو قاومت العلاج أو أصابت الأظافر، أو عند السكري أو نقص المناعة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7au000aeghlzzhhq1q9', 'Traitement du diabète de type 2', 'traitement-diabete-type-2', 'medicamenteux', 'Le traitement du diabète de type 2 associe une alimentation équilibrée, une activité physique régulière et, si besoin, des médicaments comme la metformine. L''objectif est de maintenir une glycémie stable pour prévenir les complications. Le suivi repose sur l''hémoglobine glyquée (HbA1c).', 'Mesures hygiéno-diététiques : alimentation équilibrée et activité physique régulière
Metformine, traitement médicamenteux de première intention
Autres antidiabétiques oraux ou injectables selon les cas
Insuline si le diabète n''est plus contrôlé autrement', 'Le diabète de type 2 est une maladie chronique : le traitement est prolongé, voire à vie, avec des ajustements réguliers selon les résultats et un contrôle de l''HbA1c tous les 3 à 6 mois.', 'Troubles digestifs avec la metformine (souvent transitoires)
Risque d''hypoglycémie avec certains traitements ou l''insuline
Prise de poids possible avec certaines molécules', 'Soif intense, urines abondantes et amaigrissement rapide
Signes d''hypoglycémie sévère (sueurs, confusion, malaise)
Plaie du pied qui ne cicatrise pas', 'Consultez un médecin en cas de glycémie déséquilibrée, d''effets indésirables des traitements ou de tout signe de complication (vue, reins, pieds).', '[{"q":"Le diabète de type 2 se guérit-il ?","a":"Il ne se guérit pas au sens strict, mais il peut être très bien contrôlé, voire mis en rémission, grâce à l''hygiène de vie et au traitement."},{"q":"Faut-il toujours de l''insuline ?","a":"Non. Beaucoup de patients sont équilibrés par les mesures hygiéno-diététiques et des comprimés. L''insuline n''est introduite que si nécessaire."}]', ARRAY['Diabète non insulinodépendant','DT2']::text[], (SELECT id FROM specialties WHERE slug='endocrinologie-et-maladies-metaboliques'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج داء السكري من النوع 2', 'يجمع علاج السكري من النوع 2 بين التغذية المتوازنة والنشاط البدني المنتظم، وعند الحاجة أدوية مثل الميتفورمين. الهدف هو الحفاظ على سكر مستقر للوقاية من المضاعفات. تعتمد المتابعة على الخضاب الغليكوزيلاتي (HbA1c).', 'تدابير غذائية وسلوكية: تغذية متوازنة ونشاط بدني منتظم
الميتفورمين، العلاج الدوائي الأول
أدوية أخرى فموية أو حقنية حسب الحالة
الأنسولين عند عدم التحكم بالمرض', NULL, NULL, NULL, 'استشر طبيباً عند اختلال السكر أو ظهور آثار جانبية أو أي علامة على مضاعفات (العين، الكلى، القدمان).', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtg1ib7000ekshlpoheokbe', 'Traitement du psoriasis', 'traitement-psoriasis', 'medicamenteux', 'Le traitement du psoriasis dépend de sa sévérité : crèmes (dérivés de la vitamine D, corticoïdes) et hydratation pour les formes localisées, photothérapie ou traitements généraux (dont biothérapies) pour les formes étendues. Le psoriasis ne se guérit pas mais se contrôle bien, avec des poussées espacées.', 'Émollients et hydratation quotidienne
Crèmes : dérivés de la vitamine D, corticoïdes locaux
Photothérapie pour les formes étendues
Traitements généraux et biothérapies pour les formes sévères', 'Le psoriasis est chronique et évolue par poussées. Le traitement se poursuit et s''adapte dans le temps selon l''étendue et le retentissement.', 'Amincissement cutané en cas d''usage prolongé de corticoïdes locaux
Surveillance nécessaire pour les traitements généraux et biothérapies', 'Psoriasis très étendu ou brutalement aggravé
Articulations douloureuses et gonflées (rhumatisme psoriasique)
Retentissement psychologique important', 'Consultez un dermatologue en cas de psoriasis étendu, résistant, associé à des douleurs articulaires ou mal vécu.', '[{"q":"Le psoriasis est-il contagieux ?","a":"Non, le psoriasis n''est pas contagieux. C''est une maladie inflammatoire chronique de la peau, non transmissible."},{"q":"Le psoriasis se guérit-il ?","a":"Il ne se guérit pas, mais les traitements actuels le contrôlent très bien et permettent d''espacer, voire de blanchir, les lésions."}]', ARRAY['Psoriasis en plaques']::text[], (SELECT id FROM specialties WHERE slug='dermatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الصدفية', 'يعتمد علاج الصدفية على شدتها: كريمات (مشتقات فيتامين د، كورتيكويدات) وترطيب للأشكال الموضعية، والعلاج الضوئي أو علاجات عامة (منها البيولوجية) للأشكال الواسعة. لا تُشفى الصدفية لكن يمكن التحكم فيها جيداً.', 'مرطبات وترطيب يومي
كريمات: مشتقات فيتامين د، كورتيكويدات موضعية
علاج ضوئي للأشكال الواسعة
علاجات عامة وبيولوجية للأشكال الشديدة', NULL, NULL, NULL, 'استشر طبيب أمراض جلدية عند صدفية واسعة أو مقاومة أو مصحوبة بآلام مفصلية أو مؤثرة نفسياً.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtei7cp000heghleom07kk7', 'Traitement du reflux gastro-œsophagien (RGO)', 'traitement-reflux-gastro-oesophagien', 'medicamenteux', 'Le traitement du reflux gastro-œsophagien associe des mesures d''hygiène de vie (repas plus légers, éviter de s''allonger après manger, perte de poids) et des médicaments réduisant l''acidité, comme les inhibiteurs de la pompe à protons. La chirurgie est réservée aux formes résistantes.', 'Mesures hygiéno-diététiques : repas légers, éviter alcool, tabac et aliments déclenchants
Surélever la tête du lit et éviter de s''allonger après les repas
Anti-acides et inhibiteurs de la pompe à protons (IPP)
Chirurgie anti-reflux dans les formes sévères ou résistantes', 'Le RGO est souvent chronique. Les IPP se prennent en cures adaptées à l''intensité des symptômes ; les mesures d''hygiène de vie sont maintenues durablement.', 'Troubles digestifs ou maux de tête avec les IPP (généralement bien tolérés)
Effets d''un usage prolongé à discuter avec le médecin', 'Difficulté ou douleur à avaler, amaigrissement inexpliqué
Vomissements de sang ou selles noires
Symptômes persistants malgré le traitement', 'Consultez en cas de symptômes persistants malgré le traitement, ou immédiatement devant un signe d''alerte (difficulté à avaler, saignement, amaigrissement).', '[{"q":"Le reflux est-il grave ?","a":"Le plus souvent bénin, il peut être gênant et chronique. Un reflux persistant doit être évalué pour éviter des complications sur l''œsophage."},{"q":"Peut-on soigner le reflux sans médicament ?","a":"Les mesures d''hygiène de vie suffisent parfois pour les formes légères. Les médicaments sont ajoutés si les symptômes persistent."}]', ARRAY['RGO','Reflux acide','Brûlures d''estomac']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'علاج الارتجاع المعدي المريئي', 'يجمع علاج الارتجاع المعدي المريئي بين تدابير نمط الحياة (وجبات أخف، تجنّب الاستلقاء بعد الأكل، إنقاص الوزن) وأدوية تقلّل الحموضة مثل مثبطات مضخة البروتون. تُخصَّص الجراحة للأشكال المقاومة.', 'تدابير غذائية: وجبات خفيفة، تجنّب الكحول والتدخين والأطعمة المحفزة
رفع رأس السرير وتجنّب الاستلقاء بعد الأكل
مضادات الحموضة ومثبطات مضخة البروتون
جراحة مضادة للارتجاع في الحالات الشديدة', NULL, NULL, NULL, 'استشر عند استمرار الأعراض رغم العلاج، أو فوراً عند علامة إنذار (صعوبة البلع، نزيف، فقدان الوزن).', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now())
ON CONFLICT (slug) DO NOTHING;


-- ─── Maladies (health_topics, kind=DISEASE) ───
INSERT INTO health_topics ("id", "kind", "term", "slug", "shortAnswer", "causes", "redFlags", "whenToConsult", "faqJson", "synonyms", "specialtyId", "relatedSlugs", "glossarySlugs", "sources", "termAr", "shortAnswerAr", "causesAr", "redFlagsAr", "whenToConsultAr", "faqJsonAr", "sourcesAr", "arReviewedAt", "reviewedAt", "status", "views", "createdAt", "updatedAt")
VALUES
  ('cmrtqrwj70009hghljjr9u1wu', 'DISEASE', 'Allergie', 'allergie', 'L''allergie est une réaction excessive du système immunitaire à une substance habituellement inoffensive (pollen, acariens, aliment, médicament). Elle se manifeste par des éternuements, un nez qui coule, de l''urticaire ou, plus rarement, une réaction grave. L''éviction et les antihistaminiques sont la base du traitement.', 'Terrain allergique héréditaire
Pollens, acariens, poils d''animaux
Certains aliments ou médicaments
Piqûres d''insectes', 'Gonflement du visage, de la gorge ou de la langue
Gêne respiratoire, sifflements, malaise (choc anaphylactique — urgence)
Urticaire généralisée d''apparition brutale', 'Consultez un allergologue pour identifier l''allergène et adapter le traitement, et appelez les secours en cas de réaction grave.', '[{"q":"Comment savoir à quoi je suis allergique ?","a":"Des tests allergologiques cutanés (prick-tests) et parfois des analyses de sang permettent d''identifier l''allergène en cause."},{"q":"Une allergie peut-elle être grave ?","a":"Rarement, mais une réaction généralisée (anaphylaxie) avec gêne respiratoire est une urgence vitale nécessitant les secours."}]', ARRAY['Réaction allergique','Terrain atopique']::text[], (SELECT id FROM specialties WHERE slug='allergologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الحساسية', 'الحساسية ردّ فعل مفرط من الجهاز المناعي تجاه مادة غير مؤذية عادة (لقاح، عث الغبار، طعام، دواء). تظهر بالعطس وسيلان الأنف والشرى، ونادراً بردّ فعل خطير. التجنّب ومضادات الهيستامين أساس العلاج.', 'أرضية تحسسية وراثية
اللقاح وعث الغبار ووبر الحيوانات
بعض الأطعمة أو الأدوية
لسعات الحشرات', 'تورّم الوجه أو الحلق أو اللسان
ضيق تنفس أو أزيز أو إغماء (صدمة تأقية — طارئ)
شرى منتشر مفاجئ', 'استشر طبيب حساسية لتحديد المُحسِّس وتكييف العلاج، واتصل بالإسعاف عند ردّ فعل خطير.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwid0005hghloqs6za7n', 'DISEASE', 'Anémie', 'anemie', 'L''anémie est une baisse du taux d''hémoglobine dans le sang, qui réduit le transport de l''oxygène. Elle provoque fatigue, pâleur et essoufflement. La cause la plus fréquente est le manque de fer. Le traitement dépend de la cause, qu''il faut toujours rechercher.', 'Carence en fer (règles abondantes, saignement digestif)
Carence en vitamines (B12, folates)
Maladies chroniques ou inflammatoires
Anomalies de l''hémoglobine', 'Essoufflement au moindre effort, palpitations
Pâleur intense, malaises
Saignements abondants ou selles noires', 'Consultez en cas de fatigue persistante avec pâleur ou essoufflement : une prise de sang précise le type d''anémie et oriente vers sa cause.', '[{"q":"L''anémie est-elle grave ?","a":"Le plus souvent bénigne et corrigeable, mais elle peut révéler une cause à traiter (saignement, carence). Il faut toujours l''explorer."},{"q":"Comment corriger une anémie par manque de fer ?","a":"Par une supplémentation en fer plusieurs mois et surtout en traitant la cause du manque de fer."}]', ARRAY['Manque de globules rouges']::text[], (SELECT id FROM specialties WHERE slug='hematologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'فقر الدم', 'فقر الدم انخفاض في نسبة الهيموغلوبين في الدم يقلّل نقل الأكسجين. يسبّب تعباً وشحوباً وضيق تنفس. أكثر الأسباب شيوعاً نقص الحديد. يعتمد العلاج على السبب الذي يجب البحث عنه دائماً.', 'نقص الحديد (دورة غزيرة، نزيف هضمي)
نقص الفيتامينات (B12، الفولات)
أمراض مزمنة أو التهابية
شذوذات الهيموغلوبين', 'ضيق تنفس عند أدنى جهد وخفقان
شحوب شديد وإغماءات
نزيف غزير أو براز أسود', 'استشر عند تعب مستمر مع شحوب أو ضيق تنفس: تحليل الدم يحدّد نوع فقر الدم ويوجّه نحو سببه.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwim0006hghls4umma4u', 'DISEASE', 'Arthrose', 'arthrose', 'L''arthrose est une usure progressive du cartilage des articulations, très fréquente avec l''âge. Elle touche surtout le genou, la hanche, la colonne et les mains, et provoque douleurs et raideur. Elle se contrôle par l''activité physique, la perte de poids et le traitement de la douleur.', 'Âge et usure articulaire
Surpoids (articulations portantes)
Antécédents de traumatisme
Hérédité et surmenage articulaire', 'Articulation rouge, chaude et très gonflée
Blocage articulaire ou perte de mobilité rapide
Douleur nocturne intense inhabituelle', 'Consultez si les douleurs articulaires deviennent gênantes, limitent vos activités ou résistent aux mesures habituelles.', '[{"q":"Faut-il éviter de bouger avec de l''arthrose ?","a":"Non : l''activité physique adaptée entretient l''articulation et réduit la douleur. Le repos prolongé aggrave la raideur."},{"q":"L''arthrose est-elle inévitable avec l''âge ?","a":"Elle est fréquente, mais on peut réduire le risque et ralentir son évolution en gardant un poids sain et une activité régulière."}]', ARRAY['Ostéoarthrose','Usure articulaire']::text[], (SELECT id FROM specialties WHERE slug='rhumatologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الفصال العظمي (خشونة المفاصل)', 'الفصال العظمي تآكل تدريجي لغضروف المفاصل، شائع جداً مع التقدّم في السن. يصيب خاصة الركبة والورك والعمود واليدين، ويسبّب ألماً وتيبّساً. يمكن التحكم فيه بالنشاط البدني وإنقاص الوزن وعلاج الألم.', 'السن وتآكل المفصل
الوزن الزائد (المفاصل الحاملة)
سوابق رضّ
الوراثة والإجهاد المفصلي', 'مفصل أحمر ساخن وشديد التورّم
انحصار مفصلي أو فقدان سريع للحركة
ألم ليلي شديد غير معتاد', 'استشر إذا أصبحت آلام المفاصل مزعجة أو حدّت من نشاطك أو قاومت التدابير المعتادة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwhr0002hghln0f6rg5g', 'DISEASE', 'Asthme', 'asthme', 'L''asthme est une maladie inflammatoire chronique des bronches qui provoque des crises d''essoufflement, une toux et des sifflements. Déclenché par des allergènes, l''effort ou les infections, il se contrôle bien par un traitement de fond inhalé et l''éviction des facteurs déclenchants.', 'Terrain allergique (acariens, pollens, animaux)
Infections respiratoires
Effort, air froid, pollution
Tabac et irritants', 'Crise qui ne cède pas au traitement de secours
Essoufflement au repos, difficulté à parler
Lèvres ou ongles bleutés (urgence)', 'Consultez pour un asthme mal contrôlé (crises fréquentes, réveils nocturnes) et appelez les secours en cas de crise sévère.', '[{"q":"L''asthme se guérit-il ?","a":"Il ne se guérit pas mais se contrôle très bien : bien traité, on peut mener une vie et une activité physique normales."},{"q":"Peut-on faire du sport avec de l''asthme ?","a":"Oui, un asthme bien contrôlé permet le sport. Le médecin adapte le traitement et l''échauffement au besoin."}]', ARRAY['Maladie asthmatique']::text[], (SELECT id FROM specialties WHERE slug='pneumo-phtisiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الربو', 'الربو مرض التهابي مزمن في القصبات يسبّب نوبات ضيق تنفس وسعالاً وأزيزاً. تحفّزه المواد المسببة للحساسية أو الجهد أو العدوى، ويمكن التحكم فيه بعلاج أساسي مستنشق وتجنّب المحفزات.', 'أرضية تحسسية (عث الغبار، اللقاح، الحيوانات)
التهابات تنفسية
الجهد والهواء البارد والتلوث
التدخين والمهيّجات', 'نوبة لا تستجيب لعلاج الطوارئ
ضيق تنفس أثناء الراحة، صعوبة الكلام
ازرقاق الشفتين أو الأظافر (طارئ)', 'استشر عند ربو غير متحكَّم فيه (نوبات متكررة، استيقاظ ليلي) واتصل بالإسعاف عند نوبة شديدة.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwi70004hghlbp89pbsm', 'DISEASE', 'Dépression', 'depression', 'La dépression est une maladie fréquente qui associe tristesse durable, perte d''intérêt et de plaisir, fatigue et troubles du sommeil pendant plusieurs semaines. Ce n''est pas une faiblesse : elle se soigne bien par une psychothérapie et, selon la sévérité, des médicaments.', 'Facteurs de stress ou deuil
Antécédents personnels ou familiaux
Facteurs biologiques et hormonaux
Maladies chroniques associées', 'Idées noires ou pensées suicidaires (urgence)
Incapacité à assurer le quotidien
Aggravation rapide de l''humeur', 'Consultez sans attendre si la tristesse dure et retentit sur votre vie, et en urgence en présence d''idées suicidaires.', '[{"q":"La dépression est-elle une vraie maladie ?","a":"Oui, c''est une maladie médicale reconnue, pas une faiblesse de caractère. Elle se soigne efficacement."},{"q":"Faut-il forcément des médicaments ?","a":"Non : les formes légères à modérées répondent souvent à la psychothérapie seule. Les médicaments s''ajoutent selon la sévérité."}]', ARRAY['Épisode dépressif','Dépression nerveuse']::text[], (SELECT id FROM specialties WHERE slug='psychiatrie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الاكتئاب', 'الاكتئاب مرض شائع يجمع حزناً مستمراً وفقدان الاهتمام والمتعة وتعباً واضطراب نوم لعدة أسابيع. ليس ضعفاً: يُعالَج جيداً بالعلاج النفسي، وحسب الشدة بأدوية.', 'عوامل توتر أو حداد
سوابق شخصية أو عائلية
عوامل بيولوجية وهرمونية
أمراض مزمنة مصاحبة', 'أفكار سوداء أو انتحارية (طارئ)
عجز عن تدبير الحياة اليومية
تدهور سريع في المزاج', 'استشر دون تأخير إذا استمر الحزن وأثّر على حياتك، وطارئاً عند وجود أفكار انتحارية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwgr0000hghllle3wrpu', 'DISEASE', 'Diabète', 'diabete', 'Le diabète est une maladie chronique caractérisée par un taux de sucre (glycémie) trop élevé dans le sang. Le type 2, le plus fréquent, est lié au mode de vie et à l''hérédité ; le type 1 est auto-immun. Non contrôlé, il expose à des complications du cœur, des reins, des yeux et des nerfs.', 'Surpoids et sédentarité (type 2)
Hérédité et antécédents familiaux
Âge et alimentation déséquilibrée
Mécanisme auto-immun (type 1)', 'Soif intense, urines abondantes et amaigrissement rapide
Somnolence, confusion ou haleine fruitée (urgence)
Plaie du pied qui ne cicatrise pas', 'Consultez en cas de symptômes évocateurs, de facteurs de risque, ou pour un dépistage. Un suivi régulier de la glycémie et de l''HbA1c est essentiel.', '[{"q":"Le diabète se guérit-il ?","a":"Le diabète de type 2 ne se guérit pas mais se contrôle très bien, voire se met en rémission, par l''hygiène de vie et le traitement. Le type 1 nécessite de l''insuline à vie."},{"q":"Quels sont les premiers signes du diabète ?","a":"Soif intense, envies fréquentes d''uriner, fatigue et parfois amaigrissement. Beaucoup de diabètes de type 2 sont toutefois silencieux au début."}]', ARRAY['Diabète sucré','Hyperglycémie chronique']::text[], (SELECT id FROM specialties WHERE slug='endocrinologie-et-maladies-metaboliques'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'داء السكري', 'داء السكري مرض مزمن يتميّز بارتفاع نسبة السكر في الدم. النوع 2، الأكثر شيوعاً، مرتبط بنمط الحياة والوراثة؛ والنوع 1 مناعي ذاتي. دون تحكم، يعرّض لمضاعفات في القلب والكلى والعينين والأعصاب.', 'الوزن الزائد والخمول (النوع 2)
الوراثة والسوابق العائلية
السن والتغذية غير المتوازنة
آلية مناعية ذاتية (النوع 1)', 'عطش شديد وتبوّل غزير ونقص وزن سريع
نعاس أو تشوّش أو رائحة نفس فاكهية (طارئ)
جرح في القدم لا يلتئم', 'استشر عند أعراض موحية أو عوامل خطر أو للكشف. المتابعة المنتظمة للسكر وHbA1c أساسية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwhl0001hghlvka0a9ok', 'DISEASE', 'Hypertension artérielle', 'hypertension-arterielle', 'L''hypertension artérielle (HTA) est une pression du sang trop élevée dans les artères de façon durable. Souvent silencieuse, elle augmente le risque d''infarctus, d''AVC et d''insuffisance rénale. Elle se contrôle par l''hygiène de vie et, si besoin, des médicaments.', 'Âge, hérédité et surpoids
Excès de sel, sédentarité, stress
Tabac et alcool
Certaines maladies rénales ou hormonales', 'Maux de tête violents avec troubles de la vue
Douleur thoracique ou essoufflement soudain
Trouble de la parole ou paralysie (urgence AVC)', 'Faites contrôler votre tension régulièrement, surtout après 40 ans ou en cas de facteurs de risque. Consultez si elle reste élevée.', '[{"q":"L''hypertension est-elle dangereuse sans symptômes ?","a":"Oui. Elle est souvent silencieuse mais abîme progressivement les artères, le cœur et les reins. D''où l''importance du dépistage."},{"q":"Comment faire baisser sa tension ?","a":"Réduire le sel, bouger, perdre du poids, arrêter le tabac — et prendre un traitement si le médecin le prescrit."}]', ARRAY['HTA','Tension élevée']::text[], (SELECT id FROM specialties WHERE slug='cardiologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'ارتفاع ضغط الدم', 'ارتفاع ضغط الدم هو ضغط مرتفع باستمرار في الشرايين. غالباً صامت، ويزيد خطر الاحتشاء والسكتة والقصور الكلوي. يمكن التحكم فيه بنمط الحياة وأدوية عند الحاجة.', 'السن والوراثة والوزن الزائد
الإفراط في الملح والخمول والتوتر
التدخين والكحول
بعض أمراض الكلى أو الهرمونات', 'صداع شديد مع اضطراب الرؤية
ألم صدري أو ضيق تنفس مفاجئ
اضطراب الكلام أو شلل (طارئ سكتة)', 'افحص ضغطك بانتظام، خاصة بعد 40 سنة أو عند عوامل خطر. استشر إذا بقي مرتفعاً.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwi20003hghl2ol525ks', 'DISEASE', 'Hypothyroïdie', 'hypothyroidie', 'L''hypothyroïdie est un fonctionnement au ralenti de la glande thyroïde, qui ne produit plus assez d''hormones. Elle provoque fatigue, frilosité, prise de poids et ralentissement. Fréquente et bénigne, elle se traite efficacement par un apport d''hormone thyroïdienne.', 'Maladie auto-immune (thyroïdite de Hashimoto)
Suites de chirurgie ou de traitement de la thyroïde
Carence ou excès d''iode
Certains médicaments', 'Fatigue extrême, ralentissement important
Prise de poids rapide inexpliquée
Ralentissement du cœur, gonflement du visage', 'Consultez en cas de fatigue persistante, de frilosité et de prise de poids inexpliquée : un simple dosage sanguin de la TSH permet le diagnostic.', '[{"q":"Comment diagnostique-t-on l''hypothyroïdie ?","a":"Par une prise de sang mesurant la TSH (et parfois la T4). Un taux de TSH élevé oriente vers une hypothyroïdie."},{"q":"Le traitement est-il à vie ?","a":"Le plus souvent oui, par la lévothyroxine, avec une dose ajustée selon les contrôles sanguins."}]', ARRAY['Thyroïde lente']::text[], (SELECT id FROM specialties WHERE slug='endocrinologie-et-maladies-metaboliques'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'قصور الغدة الدرقية', 'قصور الغدة الدرقية هو تباطؤ عملها فلا تنتج ما يكفي من الهرمونات. يسبّب تعباً وبرودة وزيادة وزن وتباطؤاً. شائع وحميد، ويُعالَج بفعالية بتعويض الهرمون الدرقي.', 'مرض مناعي ذاتي (التهاب هاشيموتو)
بعد جراحة أو علاج الغدة
نقص أو زيادة اليود
بعض الأدوية', 'تعب شديد وتباطؤ كبير
زيادة وزن سريعة غير مفسّرة
تباطؤ القلب وتورّم الوجه', 'استشر عند تعب مستمر وبرودة وزيادة وزن غير مفسّرة: قياس TSH في الدم يكفي للتشخيص.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwj10008hghlgdd6kqr1', 'DISEASE', 'Migraine', 'migraine', 'La migraine est une maladie neurologique fréquente qui provoque des crises de maux de tête intenses, souvent d''un seul côté, pulsatiles, aggravées par l''effort et accompagnées de nausées ou d''une gêne à la lumière. Elle se traite par un traitement de crise et, si besoin, un traitement de fond.', 'Prédisposition héréditaire
Stress, fatigue, manque de sommeil
Certains aliments, alcool, hormones
Écrans, bruit et lumière', 'Mal de tête brutal et inhabituel « en coup de tonnerre »
Céphalée avec fièvre, raideur de nuque ou trouble de la vue
Migraine qui change de caractère', 'Consultez si les crises sont fréquentes ou invalidantes, et en urgence devant tout signe d''alerte neurologique.', '[{"q":"Migraine et mal de tête, est-ce pareil ?","a":"Non : la migraine est une maladie avec des crises typiques (douleur pulsatile, nausées, gêne à la lumière), plus intense qu''un simple mal de tête."},{"q":"La migraine se soigne-t-elle ?","a":"On ne la guérit pas, mais on la contrôle bien : traitement pris tôt pendant la crise et, si les crises sont fréquentes, traitement de fond."}]', ARRAY['Céphalée migraineuse']::text[], (SELECT id FROM specialties WHERE slug='neurologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الشقيقة', 'الشقيقة مرض عصبي شائع يسبّب نوبات صداع شديد، غالباً في جهة واحدة، نابضاً، يزداد بالجهد ويصاحبه غثيان أو انزعاج من الضوء. تُعالَج بعلاج للنوبة، وعند الحاجة بعلاج أساسي.', 'استعداد وراثي
توتر وتعب وقلة نوم
بعض الأطعمة والكحول والهرمونات
الشاشات والضجيج والضوء', 'صداع مفاجئ وغير معتاد «كالصاعقة»
صداع مع حمى أو تيبّس الرقبة أو اضطراب الرؤية
شقيقة تغيّر طابعها', 'استشر إذا كانت النوبات متكررة أو مُعيقة، وطارئاً عند أي علامة إنذار عصبية.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now()),
  ('cmrtqrwis0007hghlau8iijfy', 'DISEASE', 'Reflux gastro-œsophagien', 'reflux-gastro-oesophagien', 'Le reflux gastro-œsophagien (RGO) est la remontée du contenu acide de l''estomac vers l''œsophage. Il provoque des brûlures derrière le sternum et des remontées acides, surtout après les repas ou en position allongée. Fréquent et bénin, il peut devenir chronique.', 'Repas copieux, gras, épicés
Surpoids et grossesse
Tabac, alcool, café
Hernie hiatale', 'Difficulté ou douleur à avaler, amaigrissement
Vomissements de sang ou selles noires
Douleur thoracique inhabituelle', 'Consultez si les symptômes sont fréquents, persistent malgré les mesures simples, ou en présence d''un signe d''alerte.', '[{"q":"Le reflux est-il dangereux ?","a":"Le plus souvent bénin, mais un reflux chronique doit être évalué pour éviter des complications sur l''œsophage."},{"q":"Que faire contre les brûlures d''estomac ?","a":"Repas plus légers, éviter de s''allonger après manger, perdre du poids, et un traitement anti-acide si les symptômes persistent."}]', ARRAY['RGO','Reflux acide','Brûlures d''estomac']::text[], (SELECT id FROM specialties WHERE slug='gastro-enterologie'), ARRAY[]::text[], ARRAY[]::text[], '[{"label":"Organisation mondiale de la santé (OMS)","url":"https://www.who.int","publisher":"OMS"},{"label":"Haute Autorité de santé (HAS)","url":"https://www.has-sante.fr","publisher":"HAS"}]', 'الارتجاع المعدي المريئي', 'الارتجاع المعدي المريئي هو صعود محتوى المعدة الحمضي نحو المريء. يسبّب حرقة خلف عظم القص وارتجاعاً حمضياً، خاصة بعد الأكل أو الاستلقاء. شائع وحميد وقد يصبح مزمناً.', 'وجبات دسمة ودهنية وحارة
الوزن الزائد والحمل
التدخين والكحول والقهوة
فتق الحجاب الحاجز', 'صعوبة أو ألم في البلع ونقص وزن
تقيؤ دم أو براز أسود
ألم صدري غير معتاد', 'استشر إذا كانت الأعراض متكررة أو استمرت رغم التدابير البسيطة أو ظهرت علامة إنذار.', NULL, NULL, now(), now(), 'PUBLISHED', 0, now(), now())
